  const assetItemList = assetItems || [];
  const assetList = assets || [];
  const locationList = locations || [];
  const assignmentList = assignments || [];
  const employeeList = employees || [];

  const assetById = new Map(assetList.map((asset) => [asset.id, asset]));
  const projectById = new Map((projects || []).map((project) => [project.id, project]));
  const schemeById = new Map((schemes || []).map((scheme) => [scheme.id, scheme]));

  const getSourceLabel = (item: AssetItem) => {
    const asset = assetById.get(item.asset_id);

    if (asset?.asset_source === "project") {
      const projectName = asset.project_id ? projectById.get(asset.project_id)?.name : null;
      const schemeName = asset.scheme_id ? schemeById.get(asset.scheme_id)?.name : null;

      if (projectName && schemeName) {
        return `${projectName} + ${schemeName}`;
      }

      return projectName || schemeName || "Project";
    }

    if (asset?.asset_source === "procurement") {
      return "Procurement";
    }

    return item.item_source || "N/A";
  };

  const enrichedItems = assetItemList.map((item) => ({
    ...item,
    assetName: assetById.get(item.asset_id)?.name || "N/A",
    locationName: isStoreHolder(item)
      ? "Head Office Store"
      : locationList.find((l) => l.id === getOfficeHolderId(item))?.name || "N/A",
  }));

  const columns = [
    { key: "tag", label: "Tag", render: (value: string) => <span className="font-mono font-medium text-primary">{value}</span> },
    { key: "assetName", label: "Asset", render: (value: string, row: any) => (
      <div><p className="font-medium">{value}</p><p className="text-xs text-muted-foreground">{row.serial_number}</p></div>
    )},
    { key: "locationName", label: "Location" },
    { key: "item_status", label: "Status", render: (value: string) => <StatusBadge status={value || ""} /> },
    { key: "assignment_status", label: "Assignment", render: (value: string) => <StatusBadge status={value || ""} /> },
    { key: "functional_status", label: "Functional", render: (value: string) => <StatusBadge status={value || ""} /> },
    { key: "item_source", label: "Source", render: (_value: string, row: AssetItem) => (
      <span className="text-sm text-muted-foreground">{getSourceLabel(row)}</span>
    ) },
    { key: "warranty_expiry", label: "Warranty", render: (value: string | undefined) => {
      if (!value) return <span className="text-muted-foreground">N/A</span>;
      const expiry = new Date(value);
      return <span className={expiry < new Date() ? "text-destructive" : "text-muted-foreground"}>{expiry.toLocaleDateString()}</span>;
    }},
  ];

  const handleAddItem = () => {
    setIsModalOpen(true);
  };

  const handleSubmit = async (data: {
    assetId: string;
    locationId: string;
    itemStatus: string;
    itemCondition: string;
    functionalStatus: string;
    notes?: string;
    items: Array<{ serialNumber: string; warrantyExpiry?: string }>;
  }) => {
    await createAssetItem.mutateAsync(data);
  };

  const handleEditSubmit = async (data: {
    assetId: string;
    locationId: string;
    serialNumber?: string | null;
    warrantyExpiry?: string | null;
    itemStatus: string;
    itemCondition: string;
    functionalStatus: string;
    notes?: string;
  }) => {
    if (!editModal.item) return;
    await updateAssetItem.mutateAsync({ id: editModal.item.id, data });
    setEditModal({ open: false, item: null });
  };

  const handleAssignmentSubmit = async (data: any) => {
    await createAssignment.mutateAsync(data);
  };

  const actions = (row: any) => (
    <DropdownMenu>
      <DropdownMenuTrigger asChild><Button variant="ghost" size="icon" className="h-8 w-8"><MoreHorizontal className="h-4 w-4" /></Button></DropdownMenuTrigger>
      <DropdownMenuContent align="end">
        <DropdownMenuItem onClick={() => setDetailModal({ open: true, item: row })}><Eye className="h-4 w-4 mr-2" /> View Details</DropdownMenuItem>
        <DropdownMenuItem onClick={() => setEditModal({ open: true, item: row })}><Pencil className="h-4 w-4 mr-2" /> Edit</DropdownMenuItem>
        <DropdownMenuSeparator />
        <DropdownMenuItem onClick={() => setHistoryModal({ open: true, item: row })}>
          <History className="h-4 w-4 mr-2" /> Assignment History
        </DropdownMenuItem>
        <DropdownMenuItem onClick={() => setQrModal({ open: true, item: row })}>
          <QrCode className="h-4 w-4 mr-2" /> Generate QR Code
        </DropdownMenuItem>
        <DropdownMenuSeparator />
        <DropdownMenuItem onClick={() => setAssignmentModal({ open: true, item: row })}><UserPlus className="h-4 w-4 mr-2" /> Assign to Employee</DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );

  if (isLoading) return <MainLayout title="Asset Items" description="Track individual asset instances"><div className="flex items-center justify-center h-64"><Loader2 className="h-8 w-8 animate-spin text-muted-foreground" /></div></MainLayout>;
  return (
    <MainLayout title="Asset Items" description="Track individual asset instances">
      <PageHeader 
        title="Asset Items" 
        description="View and manage individual asset items by serial number and tag" 
        action={{ label: "Add Item", onClick: handleAddItem }} 
      />
      <DataTable
        columns={columns}
        data={enrichedItems}
        searchPlaceholder="Search by tag, serial number..."
        actions={actions}
        virtualized
      />

      <AssetItemFormModal
        open={isModalOpen}
        onOpenChange={setIsModalOpen}
        assets={assetList as any}
        locations={locationList as any}
        onSubmit={handleSubmit}
      />

      <AssetItemEditModal
        open={editModal.open}
        onOpenChange={(open) => setEditModal({ open, item: open ? editModal.item : null })}
        assetItem={editModal.item}
        assets={assetList as any}
        locations={locationList as any}
        onSubmit={handleEditSubmit}
      />

      {detailModal.item && (
        <Dialog open={detailModal.open} onOpenChange={(open) => setDetailModal({ open, item: open ? detailModal.item : null })}>
          <DialogContent className="sm:max-w-[520px]">
            <DialogHeader>
              <DialogTitle>Asset Item Details</DialogTitle>
              <DialogDescription>
                View key information for this asset item.
              </DialogDescription>
            </DialogHeader>
            <div className="space-y-3 text-sm">
              <div className="flex items-center justify-between">
                <span className="text-muted-foreground">Tag</span>
                <span className="font-mono font-medium">{detailModal.item.tag || "N/A"}</span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-muted-foreground">Asset</span>
                <span className="font-medium">{detailModal.item.assetName || "N/A"}</span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-muted-foreground">Serial Number</span>
                <span>{detailModal.item.serial_number || "N/A"}</span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-muted-foreground">Location</span>
                <span>{detailModal.item.locationName || "N/A"}</span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-muted-foreground">Status</span>
                <span>{detailModal.item.item_status || "N/A"}</span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-muted-foreground">Condition</span>
                <span>{detailModal.item.item_condition || "N/A"}</span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-muted-foreground">Functional Status</span>
                <span>{detailModal.item.functional_status || "N/A"}</span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-muted-foreground">Assignment</span>
                <span>{detailModal.item.assignment_status || "N/A"}</span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-muted-foreground">Warranty Expiry</span>
                <span>
                  {detailModal.item.warranty_expiry
                    ? new Date(detailModal.item.warranty_expiry).toLocaleDateString()
                    : "N/A"}
                </span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-muted-foreground">Notes</span>
                <span className="text-right">{detailModal.item.notes || "N/A"}</span>
              </div>
            </div>
          </DialogContent>
        </Dialog>
      )}

      <AssignmentFormModal
        open={assignmentModal.open}
        onOpenChange={(open) => setAssignmentModal({ open, item: open ? assignmentModal.item : null })}
        assetItems={assetItemList as any}
        employees={employeeList as any}
        assets={assetList as any}
        selectedAssetItem={assignmentModal.item}
        onSubmit={handleAssignmentSubmit}
      />

      {/* Assignment History Modal */}
      {historyModal.item && (
        <AssignmentHistoryModal
          open={historyModal.open}
          onOpenChange={(open) => setHistoryModal({ ...historyModal, open })}
          type="assetItem"
          targetId={historyModal.item.id}
          targetName={historyModal.item.tag || historyModal.item.serial_number || "Asset Item"}
          assignments={assignmentList}
          assetItems={assetItemList}
          employees={employeeList}
          assets={assetList}
        />
      )}

      {/* QR Code Modal */}
      {qrModal.item && (
        <QRCodeModal
          open={qrModal.open}
          onOpenChange={(open) => setQrModal({ ...qrModal, open })}
          tag={qrModal.item.tag || "N/A"}
          assetName={qrModal.item.assetName || "Unknown Asset"}
          serialNumber={qrModal.item.serial_number}
        />
      )}
    </MainLayout>
  );
}

import { useMemo, useState } from "react";
import { MainLayout } from "@/components/layout/MainLayout";
import { PageHeader } from "@/components/shared/PageHeader";
import { DataTable } from "@/components/shared/DataTable";
import { ExportButton } from "@/components/shared/ExportButton";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { MoreHorizontal, Eye, Pencil, Trash2, Loader2 } from "lucide-react";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Asset } from "@/types";
import { useNavigate } from "react-router-dom";
import { useAssets, useCreateAsset, useUpdateAsset, useDeleteAsset } from "@/hooks/useAssets";
import { useCategories } from "@/hooks/useCategories";
import { useVendors } from "@/hooks/useVendors";
import { useProjects } from "@/hooks/useProjects";
import { useSchemes } from "@/hooks/useSchemes";
import { AssetFormModal } from "@/components/forms/AssetFormModal";
import { exportToCSV, exportToJSON, filterRowsBySearch, formatDateForExport, formatCurrencyForExport, pickExportFields } from "@/lib/exportUtils";
import { usePageSearch } from "@/contexts/PageSearchContext";

function formatDimensions(asset: Asset) {
  const dims = asset.dimensions;
  if (!dims) return "N/A";
  const values = [dims.length, dims.width, dims.height];
  if (values.every((value) => value === null || value === undefined)) return "N/A";
  const [l, w, h] = values.map((value) => (value ?? "-"));
  return `${l} × ${w} × ${h} ${dims.unit || "cm"}`;
}

export default function Assets() {
  const navigate = useNavigate();

  const { data: assets, isLoading } = useAssets();
  const { data: categories } = useCategories({ assetType: "ASSET" });
  const { data: vendors } = useVendors();
  const { data: projects } = useProjects();
  const { data: schemes } = useSchemes();
  const createAsset = useCreateAsset();
  const updateAsset = useUpdateAsset();
  const deleteAsset = useDeleteAsset();
  const pageSearch = usePageSearch();

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingAsset, setEditingAsset] = useState<Asset | null>(null);

  const assetList = assets || [];
  const categoryList = categories || [];
  const vendorList = vendors || [];
  const projectList = projects || [];
  const schemeList = schemes || [];

  const enrichedAssets = assetList.map((asset) => {
    const vendor = vendorList.find((v) => v.id === asset.vendor_id);
    const project = projectList.find((p) => p.id === asset.project_id);
    const scheme = schemeList.find((s) => s.id === asset.scheme_id);
    const sourceLabel = asset.asset_source === "project" ? "Project" : "Procurement";
    const sourceDetail = asset.asset_source === "project"
      ? `${project?.name || "N/A"}${scheme ? ` · ${scheme.name}` : ""}`
      : vendor?.name || "N/A";

    return {
      ...asset,
      categoryName: categoryList.find((c) => c.id === asset.category_id)?.name || "N/A",
      vendorName: vendor?.name || "N/A",
      sourceLabel,
      sourceDetail,
      dimensionsLabel: formatDimensions(asset),
    };
  });

  const columns = [
    { key: "name", label: "Asset Name", render: (value: string, row: Asset) => (
      <div><p className="font-medium">{value}</p><p className="text-xs text-muted-foreground truncate max-w-[200px]">{row.description}</p></div>
    )},
    { key: "categoryName", label: "Category", render: (value: string) => <Badge variant="secondary" className="font-normal">{value}</Badge> },
    { key: "sourceLabel", label: "Source", render: (value: string) => <Badge variant="outline" className="font-normal">{value}</Badge> },
    { key: "sourceDetail", label: "Vendor/Project" },
    { key: "dimensionsLabel", label: "Dimensions" },
    { key: "quantity", label: "Quantity", render: (value: number) => <span className="font-medium">{value}</span> },
    { key: "unit_price", label: "Unit Price", render: (value: number) => <span className="font-medium">PKR {value?.toLocaleString("en-PK") || 0}</span> },
    { key: "acquisition_date", label: "Acquired", render: (value: string) => value ? new Date(value).toLocaleDateString() : "N/A" },
  ];

  const filteredAssets = useMemo(
    () => filterRowsBySearch(enrichedAssets as any, pageSearch?.term || ""),
    [enrichedAssets, pageSearch?.term],
  );

  const handleAddAsset = () => {
    setEditingAsset(null);
    setIsModalOpen(true);
  };

  const handleEdit = (asset: Asset) => {
    setEditingAsset(asset);
    setIsModalOpen(true);
  };

  const handleSubmit = async (data: any) => {
    if (editingAsset) {
      await updateAsset.mutateAsync({ id: editingAsset.id, data });
    } else {
      await createAsset.mutateAsync(data);
    }
  };

  const handleDelete = (id: string) => {
    if (confirm("Are you sure you want to delete this asset?")) {
      deleteAsset.mutate(id);
    }
  };

  const actions = (row: Asset) => (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button variant="ghost" size="icon" className="h-8 w-8"><MoreHorizontal className="h-4 w-4" /></Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end">
        <DropdownMenuItem onClick={() => navigate(`/assets/${row.id}`)}><Eye className="h-4 w-4 mr-2" /> View Details</DropdownMenuItem>
        <DropdownMenuItem onClick={() => handleEdit(row)}><Pencil className="h-4 w-4 mr-2" /> Edit</DropdownMenuItem>
        <DropdownMenuItem className="text-destructive" onClick={() => handleDelete(row.id)}><Trash2 className="h-4 w-4 mr-2" /> Delete</DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );

  if (isLoading) {
    return (
      <MainLayout title="Assets" description="Manage your asset catalog">
        <div className="flex items-center justify-center h-64">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      </MainLayout>
    );
  }

  const handleExportCSV = () => {
    exportToCSV(
      filteredAssets as any,
      [
        { key: "name", header: "Asset Name" },
        { key: "categoryName", header: "Category" },
        { key: "sourceLabel", header: "Source" },
        { key: "sourceDetail", header: "Vendor/Project" },
        { key: "dimensionsLabel", header: "Dimensions" },
        { key: "quantity", header: "Quantity" },
        { key: "unit_price", header: "Unit Price", formatter: (v) => formatCurrencyForExport(v as number) },
        { key: "acquisition_date", header: "Acquired", formatter: (v) => formatDateForExport(v as Date) },
      ],
      "assets",
    );
  };

  const handleExportJSON = () => {
    exportToJSON(
      pickExportFields(filteredAssets as any, [
        "name",
        "categoryName",
        "sourceLabel",
        "sourceDetail",
        "dimensionsLabel",
        "quantity",
        "unit_price",
        "acquisition_date",
      ]),
      "assets",
    );
  };

  return (
    <MainLayout title="Assets" description="Manage your asset catalog">
      <PageHeader 
        title="Assets" 
        description="View and manage all asset types in your organization" 
        action={{ label: "Add Asset", onClick: handleAddAsset }}
        extra={<ExportButton onExportCSV={handleExportCSV} onExportJSON={handleExportJSON} />}
      />
      <DataTable columns={columns} data={enrichedAssets} searchPlaceholder="Search assets..." onRowClick={(row) => navigate(`/assets/${row.id}`)} actions={actions} />
      <AssetFormModal open={isModalOpen} onOpenChange={setIsModalOpen} asset={editingAsset as any} categories={categoryList as any[]} vendors={vendorList as any[]} projects={projectList as any[]} schemes={schemeList as any[]} onSubmit={handleSubmit} />
    </MainLayout>
  );
}

import { useState } from "react";
import { MainLayout } from "@/components/layout/MainLayout";
import { PageHeader } from "@/components/shared/PageHeader";
import { DataTable } from "@/components/shared/DataTable";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { MoreHorizontal, Eye, RotateCcw, Calendar, Loader2, RefreshCw, PackageCheck } from "lucide-react";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Assignment } from "@/types";
import { useAssignments, useCreateAssignment, useRequestReturn, useReassignAsset } from "@/hooks/useAssignments";
import { useAssetItems } from "@/hooks/useAssetItems";
import { useAssets } from "@/hooks/useAssets";
import { useEmployees } from "@/hooks/useEmployees";
import { AssignmentFormModal } from "@/components/forms/AssignmentFormModal";
import { ReassignmentFormModal } from "@/components/forms/ReassignmentFormModal";
import { ReturnFormModal } from "@/components/forms/ReturnFormModal";
import { useAuth } from "@/contexts/AuthContext";

export default function Assignments() {
  const { role, user } = useAuth();
  const { data: assignments, isLoading } = useAssignments();
  const { data: assetItems } = useAssetItems();
  const { data: assets } = useAssets();
  const { data: employees } = useEmployees();
  const createAssignment = useCreateAssignment();
  const requestReturn = useRequestReturn();
  const reassignAsset = useReassignAsset();

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isReassignOpen, setIsReassignOpen] = useState(false);
  const [isReturnOpen, setIsReturnOpen] = useState(false);
  const [detailModal, setDetailModal] = useState<{ open: boolean; assignment: any | null }>({
    open: false,
    assignment: null,
  });

  const assignmentList = assignments || [];
  const assetItemList = assetItems || [];
  const assetList = assets || [];
  const employeeList = employees || [];

  const currentEmployee = user
    ? employeeList.find((employee) => employee.email?.toLowerCase() === user.email.toLowerCase())
    : undefined;

  const directorateEmployeeIds = currentEmployee?.directorate_id
    ? new Set(
        employeeList
          .filter((employee) => employee.directorate_id === currentEmployee.directorate_id)
          .map((employee) => employee.id)
      )
    : new Set<string>();

  const isLimitedRole = role === "employee" || role === "office_head";

  const visibleAssignments = assignmentList.filter((assignment) => {
    if (role === "employee") {
      return currentEmployee ? assignment.employee_id === currentEmployee.id : false;
    }
    if (role === "office_head") {
      return currentEmployee?.directorate_id
        ? directorateEmployeeIds.has(assignment.employee_id)
        : false;
    }
    return true;
  });

  const enrichedAssignments = visibleAssignments.map((assignment) => {
    const item = assetItemList.find((i) => i.id === assignment.asset_item_id);
    const asset = item ? assetList.find((a) => a.id === item.asset_id) : null;
    const employee = employeeList.find((e) => e.id === assignment.employee_id);

    return {
      ...assignment,
      assetName: asset?.name || "N/A",
      itemTag: item?.tag || "N/A",
      employeeName: employee ? `${employee.first_name} ${employee.last_name}` : "N/A",
      employeeEmail: employee?.email || "N/A",
    };
  });

  const columns = [
    {
      key: "itemTag",
      label: "Asset Tag",
      render: (value: string) => (
        <span className="font-mono font-medium text-primary">{value}</span>
      ),
    },
    {
      key: "assetName",
      label: "Asset",
      render: (value: string) => (
        <span className="font-medium">{value}</span>
      ),
    },
    {
      key: "employeeName",
      label: "Assigned To",
      render: (value: string, row: any) => (
        <div>
          <p className="font-medium">{value}</p>
          <p className="text-xs text-muted-foreground">{row.employeeEmail}</p>
        </div>
      ),
    },
    {
      key: "assigned_date",
      label: "Assigned On",
      render: (value: string) => (
        <div className="flex items-center gap-2">
          <Calendar className="h-4 w-4 text-muted-foreground" />
          {new Date(value).toLocaleDateString()}
        </div>
      ),
    },
    {
      key: "expected_return_date",
      label: "Expected Return",
      render: (value: string | undefined) => {
        if (!value) return <span className="text-muted-foreground">—</span>;
        return new Date(value).toLocaleDateString();
      },
    },
    {
      key: "is_active",
      label: "Status",
      render: (value: boolean) => (
        <Badge variant={value ? "default" : "secondary"} className={value ? "bg-success text-success-foreground" : ""}>
          {value ? "Active" : "Returned"}
        </Badge>
      ),
    },
    {
      key: "notes",
      label: "Notes",
      render: (value: string) => (
        <span className="text-sm text-muted-foreground truncate max-w-[150px] block">
          {value || "—"}
        </span>
      ),
    },
  ];

  const handleNewAssignment = () => {
    setIsModalOpen(true);
  };

  const handleSubmit = async (data: any) => {
    await createAssignment.mutateAsync(data);
  };

  const handleReturnAsset = (id: string) => {
    requestReturn.mutate({ id });
  };

  const handleReturnSubmit = async (data: { assignmentId: string }) => {
    await requestReturn.mutateAsync({ id: data.assignmentId });
  };

  const handleReassignSubmit = async (data: { assignmentId: string; newEmployeeId: string; notes?: string }) => {
    await reassignAsset.mutateAsync({
      id: data.assignmentId,
      newEmployeeId: data.newEmployeeId,
      notes: data.notes,
    });
  };

  const actions = (row: Assignment) => (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button variant="ghost" size="icon" className="h-8 w-8">
          <MoreHorizontal className="h-4 w-4" />
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end">
        <DropdownMenuItem onClick={() => setDetailModal({ open: true, assignment: row })}>
          <Eye className="h-4 w-4 mr-2" /> View Details
        </DropdownMenuItem>
        {!isLimitedRole && row.is_active && (
          <>
            <DropdownMenuSeparator />
            <DropdownMenuItem onClick={() => handleReturnAsset(row.id)}>
              <RotateCcw className="h-4 w-4 mr-2" /> Request Return
            </DropdownMenuItem>
          </>
        )}
      </DropdownMenuContent>
    </DropdownMenu>
  );

  if (isLoading) {
    return (
      <MainLayout title="Assignments" description="Track asset assignments to employees">
        <div className="flex items-center justify-center h-64">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      </MainLayout>
    );
  }

  return (
    <MainLayout title="Assignments" description="Track asset assignments to employees">
      <PageHeader
        title="Assignments"
        description="View and manage asset assignments"
        action={
          isLimitedRole
            ? undefined
            : {
                label: "New Assignment",
                onClick: handleNewAssignment,
              }
        }
        extra={
          isLimitedRole ? undefined : (
            <div className="flex gap-2">
