import { useMemo, useState } from "react";
import { MainLayout } from "@/components/layout/MainLayout";
import { PageHeader } from "@/components/shared/PageHeader";
import { DataTable } from "@/components/shared/DataTable";
import { ExportButton } from "@/components/shared/ExportButton";
import { Card, CardContent } from "@/components/ui/card";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useAssets } from "@/hooks/useAssets";
import { useAssetItems } from "@/hooks/useAssetItems";
import { useAssignments } from "@/hooks/useAssignments";
import { useEmployees } from "@/hooks/useEmployees";
import { useLocations } from "@/hooks/useLocations";
import { exportToCSV, filterRowsBySearch, formatDateForExport } from "@/lib/exportUtils";
import { usePageSearch } from "@/contexts/PageSearchContext";
import { getOfficeHolderId, isStoreHolder } from "@/lib/assetItemHolder";

type UnifiedRow = {
  id: string;
  itemType: "Capital" | "Consumable";
  itemName: string;
  identifier: string;
  status: string;
  assignedTo: string;
  assignmentType: string;
  location: string;
  assignedOn: string;
  quantity: string;
};

export default function InventoryHub() {
  const pageSearch = usePageSearch();
  const [typeFilter, setTypeFilter] = useState("all");
  const [assignmentFilter, setAssignmentFilter] = useState("all");

  const { data: assets } = useAssets();
  const { data: assetItems } = useAssetItems();
  const { data: assignments } = useAssignments();
  const { data: employees } = useEmployees();
  const { data: locations } = useLocations();

  const assetRows = useMemo(() => {
    const assetList = assets || [];
    const itemList = assetItems || [];
    const assignmentList = assignments || [];
    const employeeList = employees || [];
    const locationList = locations || [];

    const assignmentMap = assignmentList.reduce((map, assignment) => {
      if (!assignment.is_active) return map;
      const existing = map.get(assignment.asset_item_id);
      if (!existing) {
        map.set(assignment.asset_item_id, assignment);
        return map;
      }
      const existingDate = new Date(existing.assigned_date).getTime();
      const currentDate = new Date(assignment.assigned_date).getTime();
      if (currentDate > existingDate) {
        map.set(assignment.asset_item_id, assignment);
      }
      return map;
    }, new Map<string, (typeof assignmentList)[number]>());

    return itemList.map<UnifiedRow>((item) => {
      const asset = assetList.find((assetEntry) => assetEntry.id === item.asset_id);
      const activeAssignment = assignmentMap.get(item.id);
      const assignedEmployee = activeAssignment
        ? employeeList.find((employee) => employee.id === activeAssignment.employee_id)
        : undefined;
      const location = locationList.find((loc) => loc.id === getOfficeHolderId(item));

      return {
        id: `asset-${item.id}`,
        itemType: "Capital",
        itemName: asset?.name || "Unknown",
        identifier: item.tag || item.serial_number || "N/A",
        status: activeAssignment ? "Assigned" : "Unassigned",
        assignedTo: assignedEmployee
          ? `${assignedEmployee.first_name} ${assignedEmployee.last_name}`
          : "Unassigned",
        assignmentType: activeAssignment ? "Employee" : "-",
        location: isStoreHolder(item) ? "Head Office Store" : location?.name || "Unassigned",
        assignedOn: activeAssignment?.assigned_date || "",
        quantity: "1",
      };
    });
  }, [assets, assetItems, assignments, employees, locations]);

  const baseRows = useMemo(() => {
    return assetRows.filter((row) => {
      if (typeFilter === "capital" && row.itemType !== "Capital") return false;
      if (typeFilter === "consumable" && row.itemType !== "Consumable") return false;
      if (assignmentFilter === "assigned" && row.status !== "Assigned") return false;
      if (assignmentFilter === "unassigned" && row.status !== "Unassigned") return false;
      return true;
    });
  }, [assetRows, typeFilter, assignmentFilter]);

  const searchTerm = pageSearch?.term || "";
  const exportRows = useMemo(
    () => filterRowsBySearch(baseRows as any, searchTerm),
    [baseRows, searchTerm]
  );

  const columns = [
    { key: "itemType", label: "Type" },
    { key: "itemName", label: "Item" },
    { key: "identifier", label: "Identifier" },
    { key: "status", label: "Status" },
    { key: "assignedTo", label: "Assigned To" },
    { key: "assignmentType", label: "Assign Type" },
    { key: "location", label: "Location" },
    {
      key: "assignedOn",
      label: "Assigned On",
      render: (value: string) => formatDateForExport(value),
    },
    { key: "quantity", label: "Qty" },
  ];

  const handleExportCSV = () => {
    exportToCSV(
      exportRows as any,
      [
        { key: "itemType", header: "Type" },
        { key: "itemName", header: "Item" },
        { key: "identifier", header: "Identifier" },
        { key: "status", header: "Status" },
        { key: "assignedTo", header: "Assigned To" },
        { key: "assignmentType", header: "Assign Type" },
        { key: "location", header: "Location" },
        { key: "assignedOn", header: "Assigned On", formatter: (v) => formatDateForExport(v as string) },
        { key: "quantity", header: "Qty" },
      ],
      "inventory-assignments"
    );
  };

  return (
    <MainLayout title="Inventory & Assignments" description="Unified view of assets, consumables, and assignments">
      <PageHeader
        title="Inventory & Assignments"
        description="One view for asset items and consumable assignments"
        extra={<ExportButton onExportCSV={handleExportCSV} />}
      />

      <Card className="mb-6">
        <CardContent className="pt-6">
          <div className="flex flex-wrap items-center gap-4">
            <div className="flex items-center gap-2">
              <span className="text-sm font-medium">Filter:</span>
            </div>
            <Select value={typeFilter} onValueChange={setTypeFilter}>
              <SelectTrigger className="w-[180px]">
                <SelectValue placeholder="Type" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All Types</SelectItem>
                <SelectItem value="capital">Capital Assets</SelectItem>
                <SelectItem value="consumable">Consumables</SelectItem>
              </SelectContent>
            </Select>
            <Select value={assignmentFilter} onValueChange={setAssignmentFilter}>
              <SelectTrigger className="w-[180px]">
                <SelectValue placeholder="Assignment" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All Assignments</SelectItem>
                <SelectItem value="assigned">Assigned</SelectItem>
                <SelectItem value="unassigned">Unassigned</SelectItem>
              </SelectContent>
            </Select>
          </div>
        </CardContent>
      </Card>

      <DataTable columns={columns} data={baseRows as any} searchable />
    </MainLayout>
  );
}

import { useState, useEffect } from 'react';
import { useNavigate, useLocation, Link } from 'react-router-dom';
import { useAuth } from '@/contexts/AuthContext';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Loader2, AlertCircle, Eye, EyeOff, ShieldAlert } from 'lucide-react';
import epaLogo from '@/assets/epa-logo.jpg';
import { CaptchaChallenge } from '@/components/auth/CaptchaChallenge';
import { 
  loginSchema, 
  recordFailedAttempt, 
  clearLoginAttempts, 
  isAccountLocked 
} from '@/lib/securityUtils';
import { auditLog } from '@/lib/auditLog';

export default function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [isCaptchaVerified, setIsCaptchaVerified] = useState(false);
  const [lockoutInfo, setLockoutInfo] = useState({ locked: false, remainingMinutes: 0 });
  const [fieldErrors, setFieldErrors] = useState<{ email?: string; password?: string }>({});

  const { login } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();

  const from = location.state?.from?.pathname || '/';

  // Check lockout status on mount and periodically
  useEffect(() => {
    const checkLockout = () => {
      setLockoutInfo(isAccountLocked());
    };
    checkLockout();
    const interval = setInterval(checkLockout, 10000); // Check every 10 seconds
    return () => clearInterval(interval);
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setFieldErrors({});

    // Check if account is locked
    const lockStatus = isAccountLocked();
    if (lockStatus.locked) {
      setLockoutInfo(lockStatus);
      return;
    }

    // Validate CAPTCHA
    if (!isCaptchaVerified) {
      setError('Please complete the security check');
      return;
    }

    // Validate inputs with zod
    const validation = loginSchema.safeParse({ email, password });
    if (!validation.success) {
      const errors: { email?: string; password?: string } = {};
      validation.error.errors.forEach((err) => {
        if (err.path[0] === 'email') errors.email = err.message;
        if (err.path[0] === 'password') errors.password = err.message;
      });
      setFieldErrors(errors);
      return;
    }

    setIsLoading(true);

    try {
      await login(email, password);
      clearLoginAttempts();
      auditLog.loginSuccess(email);
      navigate(from, { replace: true });
    } catch (err: any) {
      const attemptResult = recordFailedAttempt();
      auditLog.loginFailed(email, err.message);
      if (attemptResult.isLocked) {
        setError(`Too many failed attempts. Account locked for ${attemptResult.lockoutMinutes} minutes.`);
        setLockoutInfo({ locked: true, remainingMinutes: attemptResult.lockoutMinutes });
      } else if (attemptResult.remainingAttempts > 0) {
        setError(`${err.message || 'Failed to login'} (${attemptResult.remainingAttempts} attempts remaining)`);
      } else {
        setError(err.message || 'Failed to login. Please check your credentials.');
      }
    } finally {
      setIsLoading(false);
    }
  };

  const isFormDisabled = isLoading || lockoutInfo.locked;

  return (
    <div className="min-h-screen flex items-center justify-center bg-background p-4">
      <div className="w-full max-w-md">
        <div className="text-center mb-6">
          <div className="mx-auto mb-4 h-12 w-12 rounded-full bg-primary/10 flex items-center justify-center">
            <img
              src={epaLogo}
              alt="EPA Logo"
              className="h-7 w-7 object-contain"
            />
          </div>
          <h1 className="text-2xl font-bold text-foreground">EPA AMS</h1>
          <p className="text-sm text-muted-foreground">Asset Management System</p>
        </div>

        <Card>
          <CardHeader className="text-center space-y-1">
            <CardTitle>Staff Login</CardTitle>
            <CardDescription>
              Sign in to access the staff dashboard.
            </CardDescription>
          </CardHeader>

          <form onSubmit={handleSubmit}>
            <CardContent className="space-y-4">
              {lockoutInfo.locked && (
                <Alert variant="destructive">
                  <ShieldAlert className="h-4 w-4" />
                  <AlertDescription>
                    Account temporarily locked. Please try again in {lockoutInfo.remainingMinutes} minute(s).
                  </AlertDescription>
                </Alert>
              )}

              {error && !lockoutInfo.locked && (
                <Alert variant="destructive">
                  <AlertCircle className="h-4 w-4" />
                  <AlertDescription>{error}</AlertDescription>
                </Alert>
              )}

              <div className="space-y-2">
                <Label htmlFor="email">Email</Label>
                <Input
                  id="email"
                  type="email"
                  placeholder="name@EPAPunjab.gov.pk"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                  disabled={isFormDisabled}
                  className={`h-11 ${fieldErrors.email ? 'border-destructive' : ''}`}
                  autoComplete="email"
                />
                {fieldErrors.email && (
                  <p className="text-xs text-destructive">{fieldErrors.email}</p>
                )}
              </div>

              <div className="space-y-2">
                <div className="flex items-center justify-between">
                  <Label htmlFor="password">Password</Label>
                  <Link 
                    to="/forgot-password" 
                    className="text-sm text-primary hover:underline"
                  >
                    Forgot password?
                  </Link>
                </div>
                <div className="relative">
                  <Input
                    id="password"
                    type={showPassword ? 'text' : 'password'}
                    placeholder="••••••••"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    required
                    disabled={isFormDisabled}
                    className={`h-11 pr-10 ${fieldErrors.password ? 'border-destructive' : ''}`}
                    autoComplete="current-password"
                  />
                  <Button
                    type="button"
                    variant="ghost"
                    size="icon"
                    className="absolute right-0 top-0 h-11 w-11 text-muted-foreground hover:text-foreground"
                    onClick={() => setShowPassword(!showPassword)}
                    tabIndex={-1}
                  >
                    {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                  </Button>
                </div>
                {fieldErrors.password && (
                  <p className="text-xs text-destructive">{fieldErrors.password}</p>
                )}
              </div>

              {/* CAPTCHA */}
              <CaptchaChallenge 
                onVerify={setIsCaptchaVerified} 
                isVerified={isCaptchaVerified} 
              />
            </CardContent>

            <CardFooter className="flex flex-col gap-4">
              <Button 
                type="submit" 
                className="w-full h-11" 
                disabled={isFormDisabled || !isCaptchaVerified}
              >
                {isLoading ? (
                  <>
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    Signing in...
                  </>
                ) : (
                  'Sign in'
                )}
              </Button>

              <p className="text-sm text-center text-muted-foreground">
                Contact your administrator to request an account
              </p>
            </CardFooter>
          </form>
        </Card>
      </div>
    </div>
  );
}

import { useState } from "react";
import { MainLayout } from "@/components/layout/MainLayout";
import { PageHeader } from "@/components/shared/PageHeader";
import { DataTable } from "@/components/shared/DataTable";
import { StatusBadge } from "@/components/shared/StatusBadge";
import { Button } from "@/components/ui/button";
import { MoreHorizontal, Eye, Pencil, CheckCircle, XCircle, Loader2, FileUp } from "lucide-react";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import type { MaintenanceRecord } from '@/types';
import { useMaintenance, useCreateMaintenance, useCompleteMaintenance, useUpdateMaintenance } from "@/hooks/useMaintenance";
import { useAssetItems } from "@/hooks/useAssetItems";
import { useAssets } from "@/hooks/useAssets";
import { MaintenanceFormModal } from "@/components/forms/MaintenanceFormModal";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { toast } from "sonner";
import { documentService, documentLinkService } from "@/services";
import type { DocumentStatus, DocumentType } from "@/services/documentService";
import { RecordDetailModal } from "@/components/records/RecordDetailModal";
import { getOfficeHolderId } from "@/lib/assetItemHolder";

export default function Maintenance() {
  const { data: maintenanceRecords, isLoading } = useMaintenance();
  const { data: assetItems } = useAssetItems();
  const { data: assets } = useAssets();
  const createMaintenance = useCreateMaintenance();
  const completeMaintenance = useCompleteMaintenance();
  const updateMaintenance = useUpdateMaintenance();

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingMaintenance, setEditingMaintenance] = useState<MaintenanceRecord | null>(null);
  const [docModal, setDocModal] = useState<{ open: boolean; record: MaintenanceRecord | null }>({
    open: false,
    record: null,
  });
  const [docType, setDocType] = useState<DocumentType>('MaintenanceJobCard');
  const [docStatus, setDocStatus] = useState<DocumentStatus>('Final');
  const [docTitle, setDocTitle] = useState('');
  const [docFile, setDocFile] = useState<File | null>(null);
  const [docError, setDocError] = useState<string | null>(null);
  const [docSubmitting, setDocSubmitting] = useState(false);
  const [recordModal, setRecordModal] = useState<{ open: boolean; record: MaintenanceRecord | null }>({
    open: false,
    record: null,
  });

  const maintenanceList = maintenanceRecords || [];
  const assetItemList = assetItems || [];
  const assetList = assets || [];

  const enrichedRecords = maintenanceList.map((record) => {
    const item = assetItemList.find((i) => i.id === record.asset_item_id);
    const asset = item ? assetList.find((a) => a.id === item.asset_id) : null;

    return {
      ...record,
      assetName: asset?.name || "N/A",
      itemTag: item?.tag || "N/A",
    };
  });

  const columns = [
    {
      key: "itemTag",
      label: "Asset Tag",
      render: (value: string) => (
        <span className="font-mono font-medium text-primary">{value}</span>
      ),
    },
    {
      key: "assetName",
      label: "Asset",
      render: (value: string) => (
        <span className="font-medium">{value}</span>
      ),
    },
    {
      key: "description",
      label: "Description",
      render: (value: string) => (
        <span className="text-sm max-w-[200px] truncate block">{value}</span>
      ),
    },
    {
      key: "maintenance_status",
      label: "Status",
      render: (value: string) => <StatusBadge status={value || ""} />,
    },
    {
      key: "scheduled_date",
      label: "Scheduled",
      render: (value: string | undefined) => {
        if (!value) return <span className="text-muted-foreground">—</span>;
        return new Date(value).toLocaleDateString();
      },
    },
    {
      key: "cost",
      label: "Cost",
      render: (value: number) => (
        <span className="font-medium">PKR {(value || 0).toLocaleString("en-PK")}</span>
      ),
    },
    {
      key: "performed_by",
      label: "Performed By",
      render: (value: string) => (
        <span className="text-muted-foreground">{value || "—"}</span>
      ),
    },
  ];

  const handleScheduleMaintenance = () => {
    setEditingMaintenance(null);
    setIsModalOpen(true);
  };

  const handleEdit = (record: MaintenanceRecord) => {
    setEditingMaintenance(record);
    setIsModalOpen(true);
  };

  const handleSubmit = async (data: any) => {
    if (editingMaintenance) {
      await updateMaintenance.mutateAsync({ id: editingMaintenance.id, data });
    } else {
      await createMaintenance.mutateAsync(data);
    }
  };

  const handleComplete = (id: string) => {
    completeMaintenance.mutate({ 
      id, 
      completedDate: new Date().toISOString(),
      notes: "Completed via dashboard"
    });
  };

  const handleCancel = (id: string) => {
    updateMaintenance.mutate({ 
      id, 
      data: { maintenanceStatus: 'Cancelled' }
    });
  };

  const openDocModal = (record: MaintenanceRecord) => {
    setDocModal({ open: true, record });
  };

  const openRecordModal = (record: MaintenanceRecord) => {
    setRecordModal({ open: true, record });
  };

  const closeDocModal = () => {
    setDocModal({ open: false, record: null });
    setDocType('MaintenanceJobCard');
    setDocStatus('Final');
    setDocTitle('');
    setDocFile(null);
    setDocError(null);
  };

  const closeRecordModal = () => {
    setRecordModal({ open: false, record: null });
  };

  const getAssetLabel = (record: MaintenanceRecord) => {
    const item = assetItemList.find((i) => i.id === record.asset_item_id);
    const asset = item ? assetList.find((a) => a.id === item.asset_id) : null;
    const tag = item?.tag || item?.serial_number || 'Asset Item';
    return asset ? `${asset.name} (${tag})` : tag;
  };

  const handleDocSubmit = async () => {
    if (!docModal.record) return;
    if (!docFile) {
      setDocError('Select a file to upload.');
      return;
    }
    setDocSubmitting(true);
    setDocError(null);
    try {
      const item = assetItemList.find((i) => i.id === docModal.record?.asset_item_id);
      const officeId = item ? getOfficeHolderId(item) || undefined : undefined;
      const title = docTitle.trim() || `${docType} - ${getAssetLabel(docModal.record)}`;

      const document = await documentService.create({
        title,
        docType,
        status: docStatus,
        officeId,
      });
      await documentService.upload(document.id, docFile);
      await documentLinkService.create({
        documentId: document.id,
        entityType: 'MaintenanceRecord',
        entityId: docModal.record.id,
      });
      toast.success('Document uploaded and linked.');
      closeDocModal();
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Failed to upload document';
      toast.error(message);
    } finally {
      setDocSubmitting(false);
    }
  };

  const actions = (row: MaintenanceRecord & { assetName: string; itemTag: string }) => (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button variant="ghost" size="icon" className="h-8 w-8">
          <MoreHorizontal className="h-4 w-4" />
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end">
        <DropdownMenuItem onClick={() => openRecordModal(row)}>
          <Eye className="h-4 w-4 mr-2" /> Digital File
        </DropdownMenuItem>
        <DropdownMenuItem onClick={() => handleEdit(row)}>
          <Pencil className="h-4 w-4 mr-2" /> Edit
        </DropdownMenuItem>
        <DropdownMenuItem onClick={() => openDocModal(row)}>
          <FileUp className="h-4 w-4 mr-2" /> Upload Docs
        </DropdownMenuItem>
        <DropdownMenuSeparator />
        {row.maintenance_status !== 'Completed' && (
          <DropdownMenuItem onClick={() => handleComplete(row.id)}>
            <CheckCircle className="h-4 w-4 mr-2" /> Mark Complete
          </DropdownMenuItem>
        )}
        {row.maintenance_status === 'Scheduled' && (
          <DropdownMenuItem 
            className="text-destructive"
            onClick={() => handleCancel(row.id)}
          >
            <XCircle className="h-4 w-4 mr-2" /> Cancel
          </DropdownMenuItem>
        )}
      </DropdownMenuContent>
    </DropdownMenu>
  );

  if (isLoading) {
    return (
      <MainLayout title="Maintenance" description="Track asset maintenance and repairs">
        <div className="flex items-center justify-center h-64">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      </MainLayout>
    );
  }

  return (
    <MainLayout title="Maintenance" description="Track asset maintenance and repairs">
      <PageHeader
        title="Maintenance Records"
        description="Schedule and track maintenance activities for assets"
        action={{
          label: "Schedule Maintenance",
          onClick: handleScheduleMaintenance,
        }}
      />

      <DataTable
        columns={columns}
        data={enrichedRecords}
        searchPlaceholder="Search maintenance records..."
        actions={actions}
      />

      <MaintenanceFormModal
        open={isModalOpen}
        onOpenChange={setIsModalOpen}
        maintenance={editingMaintenance as any}
        assetItems={assetItemList as any}
        assets={assetList as any}
        onSubmit={handleSubmit}
      />

      {docModal.record && (
        <Dialog open={docModal.open} onOpenChange={(open) => (open ? null : closeDocModal())}>
          <DialogContent className="sm:max-w-[520px]">
            <DialogHeader>
              <DialogTitle>Upload Maintenance Document</DialogTitle>
              <DialogDescription>
                Attach a job card or invoice before completing maintenance.
              </DialogDescription>
            </DialogHeader>
            <div className="space-y-4">
              <div className="space-y-2">
                <Label>Document Type</Label>
                <Select value={docType} onValueChange={(value) => setDocType(value as DocumentType)}>
                  <SelectTrigger>
                    <SelectValue placeholder="Select type" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="MaintenanceJobCard">Maintenance Job Card</SelectItem>
                    <SelectItem value="Invoice">Invoice</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label>Document Status</Label>
                <Select value={docStatus} onValueChange={(value) => setDocStatus(value as DocumentStatus)}>
                  <SelectTrigger>
                    <SelectValue placeholder="Select status" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="Draft">Draft</SelectItem>
                    <SelectItem value="Final">Final</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label htmlFor="docTitle">Title</Label>
                <Input
                  id="docTitle"
                  value={docTitle}
                  onChange={(e) => setDocTitle(e.target.value)}
                  placeholder={`${docType} - ${getAssetLabel(docModal.record)}`}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="docFile">File *</Label>
                <Input
                  id="docFile"
                  type="file"
                  accept="application/pdf,image/jpeg,image/png"
                  onChange={(e) => setDocFile(e.target.files?.[0] || null)}
                />
                {docError && <p className="text-sm text-destructive">{docError}</p>}
              </div>
              <div className="flex justify-end gap-2">
                <Button variant="outline" onClick={closeDocModal} disabled={docSubmitting}>
                  Cancel
                </Button>
                <Button onClick={handleDocSubmit} disabled={docSubmitting}>
                  {docSubmitting && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                  Upload & Link
                </Button>
              </div>
            </div>
          </DialogContent>
        </Dialog>
      )}

      <RecordDetailModal
        open={recordModal.open}
        onOpenChange={(open) => (open ? null : closeRecordModal())}
        lookup={{
          recordType: "MAINTENANCE",
          maintenanceRecordId: recordModal.record?.id,
        }}
        title={
          recordModal.record
            ? `Maintenance File - ${getAssetLabel(recordModal.record)}`
            : "Maintenance File"
        }
      />
    </MainLayout>
  );
}

import { MainLayout } from "@/components/layout/MainLayout";
import { useAuth } from "@/contexts/AuthContext";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Mail, Shield, Calendar, LogOut, KeyRound } from "lucide-react";
import { useNavigate } from "react-router-dom";
import { useState } from "react";
import api from "@/lib/api";
import { toast } from "sonner";

export default function Profile() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [currentPassword, setCurrentPassword] = useState("");
  const [newPassword, setNewPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [isUpdatingPassword, setIsUpdatingPassword] = useState(false);

  const handleLogout = () => {
    logout();
    navigate("/login");
  };

  const handlePasswordChange = async (event: React.FormEvent) => {
    event.preventDefault();
    if (newPassword !== confirmPassword) {
      toast.error("New passwords do not match");
      return;
    }

    setIsUpdatingPassword(true);
    try {
      await api.post("/auth/change-password", {
        oldPassword: currentPassword,
        newPassword,
      });
      toast.success("Password updated");
      setCurrentPassword("");
      setNewPassword("");
      setConfirmPassword("");
    } catch (error: any) {
      toast.error(error?.message || "Failed to update password");
    } finally {
      setIsUpdatingPassword(false);
    }
  };

  if (!user) {
    return (
      <MainLayout title="Profile" description="User profile">
        <div className="flex items-center justify-center h-64">
          <p className="text-muted-foreground">User not found</p>
        </div>
      </MainLayout>
    );
  }

  const initials = user.email
    ? user.email.substring(0, 2).toUpperCase()
    : "U";
  const roleLabel = (() => {
    switch (user.role) {
      case "org_admin":
        return "Administrator";
      case "office_head":
        return "Office Head";
      case "caretaker":
        return "Caretaker";
      case "employee":
        return "Employee";
      default:
        return "User";
    }
  })();

  return (
    <MainLayout title="My Profile" description="View and manage your account">
      <div className="max-w-2xl mx-auto space-y-6">
        {/* Profile Header */}
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center gap-6">
              <Avatar className="h-24 w-24">
                <AvatarFallback className="bg-primary/10 text-primary text-2xl font-bold">
                  {initials}
                </AvatarFallback>
              </Avatar>
              <div className="space-y-2">
                <h1 className="text-2xl font-bold">{user.email}</h1>
                <div className="flex items-center gap-2">
                  <Badge variant="secondary" className="bg-primary/10 text-primary">
                    <Shield className="mr-1 h-3 w-3" />
                    {roleLabel}
                  </Badge>
                </div>
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Account Details */}
        <Card>
          <CardHeader>
            <CardTitle>Account Details</CardTitle>
            <CardDescription>Your account information</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="flex items-center gap-4 p-4 rounded-lg bg-muted/50">
              <Mail className="h-5 w-5 text-muted-foreground" />
              <div>
                <p className="text-sm text-muted-foreground">Email Address</p>
                <p className="font-medium">{user.email}</p>
              </div>
            </div>

            <div className="flex items-center gap-4 p-4 rounded-lg bg-muted/50">
              <Shield className="h-5 w-5 text-muted-foreground" />
              <div>
                <p className="text-sm text-muted-foreground">Role</p>
                <p className="font-medium">{roleLabel}</p>
              </div>
            </div>

            <div className="flex items-center gap-4 p-4 rounded-lg bg-muted/50">
              <Calendar className="h-5 w-5 text-muted-foreground" />
              <div>
                <p className="text-sm text-muted-foreground">User ID</p>
                <p className="font-mono text-sm">{user.id}</p>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle>Change Password</CardTitle>
            <CardDescription>Update your password using your current credentials</CardDescription>
          </CardHeader>
          <CardContent>
            <form onSubmit={handlePasswordChange} className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="current-password">Current Password</Label>
                <Input
                  id="current-password"
                  type="password"
                  value={currentPassword}
                  onChange={(event) => setCurrentPassword(event.target.value)}
                  required
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="new-password">New Password</Label>
                <Input
                  id="new-password"
                  type="password"
                  value={newPassword}
                  onChange={(event) => setNewPassword(event.target.value)}
                  required
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="confirm-password">Confirm New Password</Label>
                <Input
                  id="confirm-password"
                  type="password"
                  value={confirmPassword}
                  onChange={(event) => setConfirmPassword(event.target.value)}
                  required
                />
              </div>
              <Button type="submit" className="w-full" disabled={isUpdatingPassword}>
                <KeyRound className="mr-2 h-4 w-4" />
                {isUpdatingPassword ? "Updating..." : "Update Password"}
              </Button>
            </form>
          </CardContent>
        </Card>

        {/* Actions */}
        <Card>
          <CardHeader>
            <CardTitle>Account Actions</CardTitle>
          </CardHeader>
          <CardContent>
            <Button variant="destructive" onClick={handleLogout} className="w-full">
              <LogOut className="mr-2 h-4 w-4" />
              Sign Out
            </Button>
          </CardContent>
        </Card>
      </div>
    </MainLayout>
  );
}

import { useMemo, useState } from "react";
import { MainLayout } from "@/components/layout/MainLayout";
import { PageHeader } from "@/components/shared/PageHeader";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { FolderKanban, Calendar, MoreHorizontal, Pencil, Trash2, Eye, Loader2 } from "lucide-react";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { toast } from "sonner";
import { useProjects, useCreateProject, useUpdateProject, useDeleteProject } from "@/hooks/useProjects";
import { ProjectFormModal } from "@/components/forms/ProjectFormModal";
import { Project } from "@/types";
import { usePageSearch } from "@/contexts/PageSearchContext";
import { ViewModeToggle } from "@/components/shared/ViewModeToggle";
import { useViewMode } from "@/hooks/useViewMode";
import { DataTable } from "@/components/shared/DataTable";

export default function Projects() {
  const { data: projects, isLoading } = useProjects();
  const createProject = useCreateProject();
  const updateProject = useUpdateProject();
  const deleteProject = useDeleteProject();

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingProject, setEditingProject] = useState<Project | null>(null);
  const { mode: viewMode, setMode: setViewMode } = useViewMode("projects");
  const pageSearch = usePageSearch();
  const searchTerm = (pageSearch?.term || "").trim().toLowerCase();

  const filteredProjects = useMemo(
    () =>
      (projects || []).filter((project) => {
        if (!searchTerm) return true;
        return [project.code, project.name, project.description, project.is_active ? "active" : "inactive"]
          .join(" ")
          .toLowerCase()
          .includes(searchTerm);
      }),
    [projects, searchTerm]
  );

  const handleAddProject = () => {
    setEditingProject(null);
    setIsModalOpen(true);
  };

  const handleEdit = (project: Project) => {
    setEditingProject(project);
    setIsModalOpen(true);
  };

  const handleSubmit = async (data: any) => {
    if (editingProject) {
      await updateProject.mutateAsync({ id: editingProject.id, data });
    } else {
      await createProject.mutateAsync(data);
    }
  };

  const handleDelete = (id: string) => {
    if (confirm("Are you sure you want to delete this project?")) {
      deleteProject.mutate(id);
    }
  };

  const columns = [
    {
      key: "name",
      label: "Project",
      render: (value: string, row: Project) => (
        <div>
          <p className="font-medium">{value}</p>
          <p className="text-xs text-muted-foreground">{row.code || "No code"}</p>
        </div>
      ),
    },
