export default function UserManagement() {
  const queryClient = useQueryClient();
  const pageSearch = usePageSearch();
  const searchQuery = pageSearch?.term || "";
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(50);
  const [editingUser, setEditingUser] = useState<UserWithDetails | null>(null);
  const [selectedRole, setSelectedRole] = useState<AppRole | "">("");
  const [selectedLocation, setSelectedLocation] = useState<string>("");
  const [isCreateDialogOpen, setIsCreateDialogOpen] = useState(false);
  const [deleteUserId, setDeleteUserId] = useState<string | null>(null);
  const [resetPasswordUser, setResetPasswordUser] = useState<UserWithDetails | null>(null);
  const [newPassword, setNewPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");

  // New user form state
  const [newUserEmail, setNewUserEmail] = useState("");
  const [newUserPassword, setNewUserPassword] = useState("");
  const [newUserFirstName, setNewUserFirstName] = useState("");
  const [newUserLastName, setNewUserLastName] = useState("");
  const [newUserRole, setNewUserRole] = useState<AppRole | "">("");
  const [newUserLocation, setNewUserLocation] = useState<string>("");
  const [newUserLocationPickerOpen, setNewUserLocationPickerOpen] = useState(false);

  // Fetch all users with their profiles and roles
  const { data: users = { items: [], page: 1, limit: 50, total: 0, hasMore: false }, isLoading: usersLoading } =
    useQuery({
    queryKey: ["users-management", page, pageSize, searchQuery],
    queryFn: () => userService.getPaged({ page, limit: pageSize, search: searchQuery || undefined }),
    });

  useEffect(() => {
    setPage(1);
  }, [searchQuery, pageSize]);

  // Fetch all locations
  const { data: locations = [] } = useQuery({
    queryKey: ["locations-management"],
    queryFn: () => locationService.getAll() as Promise<Location[]>,
  });

  // Update user role mutation
  const updateRoleMutation = useMutation({
    mutationFn: ({ userId, role }: { userId: string; role: AppRole }) =>
      userService.updateRole(userId, role),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["users-management"] });
      toast.success("User role updated successfully");
    },
    onError: (error) => {
      toast.error("Failed to update role: " + error.message);
    },
  });

  // Update user location mutation
  const updateLocationMutation = useMutation({
    mutationFn: ({ userId, locationId }: { userId: string; locationId: string | null }) =>
      userService.updateLocation(userId, locationId),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["users-management"] });
      toast.success("User location updated successfully");
    },
    onError: (error) => {
      toast.error("Failed to update location: " + error.message);
    },
  });

  // Create user mutation
  const createUserMutation = useMutation({
    mutationFn: (data: { 
      email: string; 
      password: string; 
      firstName?: string; 
      lastName?: string;
      role?: string;
      locationId?: string;
    }) =>
      userService.create({
        email: data.email,
        password: data.password,
        firstName: data.firstName,
        lastName: data.lastName,
        role: data.role as AppRole,
        locationId: data.locationId,
      }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["users-management"] });
      toast.success("User created successfully");
      setIsCreateDialogOpen(false);
      resetNewUserForm();
    },
    onError: (error) => {
      toast.error("Failed to create user: " + error.message);
    },
  });

  // Delete user mutation
  const deleteUserMutation = useMutation({
    mutationFn: (userId: string) => userService.delete(userId),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["users-management"] });
      toast.success("User deleted successfully");
      setDeleteUserId(null);
    },
    onError: (error) => {
      toast.error("Failed to delete user: " + error.message);
    },
  });

  // Reset password mutation
  const resetPasswordMutation = useMutation({
    mutationFn: ({ userId, newPassword }: { userId: string; newPassword: string }) =>
      userService.resetPassword(userId, newPassword),
    onSuccess: () => {
      toast.success("Password reset successfully");
      setResetPasswordUser(null);
      setNewPassword("");
      setConfirmPassword("");
    },
    onError: (error) => {
      toast.error("Failed to reset password: " + error.message);
    },
  });

  const resetNewUserForm = () => {
    setNewUserEmail("");
    setNewUserPassword("");
    setNewUserFirstName("");
    setNewUserLastName("");
    setNewUserRole("");
    setNewUserLocation("");
    setNewUserLocationPickerOpen(false);
  };

  const handleCreateUser = async () => {
    const errors: string[] = [];
    if (!newUserFirstName.trim()) errors.push("First name is required");
    if (!newUserLastName.trim()) errors.push("Last name is required");
    if (!newUserEmail.trim()) errors.push("Email is required");
    if (!newUserPassword) errors.push("Password is required");
    if (!newUserRole) errors.push("Role is required");
    if (!newUserLocation) errors.push("Location is required");

    if (errors.length > 0) {
      toast.error(errors.join(" | "));
      return;
    }

    await createUserMutation.mutateAsync({
      email: newUserEmail.trim(),
      password: newUserPassword,
      firstName: newUserFirstName.trim(),
      lastName: newUserLastName.trim(),
      role: newUserRole as AppRole,
      locationId: newUserLocation,
    });
  };

  const handleDeleteUser = (userId: string) => {
    setDeleteUserId(userId);
  };

  const confirmDeleteUser = () => {
    if (deleteUserId) {
      deleteUserMutation.mutate(deleteUserId);
    }
  };

  const handleEditUser = (user: UserWithDetails) => {
    setEditingUser(user);
    setSelectedRole(user.role || "");
    setSelectedLocation(user.location_id || "none");
  };

  const handleSaveUser = async () => {
    if (!editingUser) return;

    try {
      if (selectedRole && selectedRole !== editingUser.role) {
        await updateRoleMutation.mutateAsync({ 
          userId: editingUser.user_id, 
          role: selectedRole as AppRole 
        });
      }

      const newLocationId = selectedLocation === "none" ? null : selectedLocation;
      if (newLocationId !== editingUser.location_id) {
        await updateLocationMutation.mutateAsync({ 
          userId: editingUser.user_id, 
          locationId: newLocationId 
        });
      }

      setEditingUser(null);
    } catch (error) {
      // Error handled by mutations
    }
  };

  const visibleUsers = useMemo(() => users.items || [], [users.items]);
  const totalUsers = users.total || 0;
  const totalPages = Math.max(1, Math.ceil(totalUsers / pageSize));
  const selectedNewUserLocation = useMemo(
    () => locations.find((location) => location.id === newUserLocation) || null,
    [locations, newUserLocation]
  );

  const getRoleBadge = (role: AppRole | null) => {
    if (!role) return <Badge variant="outline">No Role</Badge>;
    return (
      <Badge className={roleColors[role]}>
        {role === "org_admin" && <Crown className="h-3 w-3 mr-1" />}
        {roleLabels[role]}
      </Badge>
    );
  };

  return (
    <MainLayout title="User Management" description="Manage users and permissions">
      <PageHeader
        title="User Management"
        description="Create, edit and manage user accounts"
        action={{
          label: "Add User",
          onClick: () => setIsCreateDialogOpen(true),
