export default function UserPermissions() {
  const [roles, setRoles] = useState<UserRole[]>(initialRoles);
  const [selectedRole, setSelectedRole] = useState<string>("super_administrator");
  const pageSearch = usePageSearch();
  const searchQuery = pageSearch?.term || "";
  const [isAddRoleOpen, setIsAddRoleOpen] = useState(false);
  const [newRoleName, setNewRoleName] = useState("");
  const [newRoleDescription, setNewRoleDescription] = useState("");

  const { data: users = [] } = useQuery({
    queryKey: ["users-management"],
    queryFn: () => userService.getAll(),
  });

  const roleCounts = useMemo(() => {
    const counts: Record<string, number> = {};
    users.forEach((user) => {
      const role = normalizeRole(user.role || "employee");
      counts[role] = (counts[role] || 0) + 1;
    });
    return counts;
  }, [users]);

  const rolesWithCounts = useMemo(
    () =>
      roles.map((role) => ({
        ...role,
        usersCount: (role.sourceRoles || [role.id]).reduce((total, roleKey) => total + (roleCounts[roleKey] || 0), 0),
      })),
    [roles, roleCounts],
  );

  const currentRole = rolesWithCounts.find((r) => r.id === selectedRole);

  const filteredPages = appPages.filter((page) =>
    page.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const groupedPages = filteredPages.reduce((acc, page) => {
    if (!acc[page.category]) {
      acc[page.category] = [];
    }
    acc[page.category].push(page);
    return acc;
  }, {} as Record<string, typeof appPages>);

  const togglePermission = (pageId: string, permission: PermissionType) => {
    setRoles((prevRoles) =>
      prevRoles.map((role) => {
        if (role.id !== selectedRole) return role;

        const currentPermissions = role.permissions[pageId] || [];
        const hasPermission = currentPermissions.includes(permission);

        let newPermissions: PermissionType[];
        if (hasPermission) {
          newPermissions = currentPermissions.filter((p) => p !== permission);
        } else {
          newPermissions = [...currentPermissions, permission];
        }

        return {
          ...role,
          permissions: {
            ...role.permissions,
            [pageId]: newPermissions,
          },
        };
      })
    );
  };

  const hasPermission = (pageId: string, permission: PermissionType): boolean => {
    if (!currentRole) return false;
    return currentRole.permissions[pageId]?.includes(permission) || false;
  };

  const handleSavePermissions = () => {
    // In production, this would save to the backend
    toast.success("Permissions saved successfully");
  };

  const handleAddRole = () => {
    if (!newRoleName.trim()) {
      toast.error("Role name is required");
      return;
    }

    const newRole: UserRole = {
      id: newRoleName.toLowerCase().replace(/\s+/g, "-"),
      name: newRoleName,
      description: newRoleDescription,
      usersCount: 0,
      permissions: appPages.reduce((acc, page) => {
        acc[page.id] = [];
        return acc;
      }, {} as Record<string, PermissionType[]>),
    };

    setRoles([...roles, newRole]);
    setSelectedRole(newRole.id);
    setNewRoleName("");
    setNewRoleDescription("");
    setIsAddRoleOpen(false);
    toast.success(`Role "${newRoleName}" created`);
  };

  const selectAllForPage = (pageId: string) => {
    setRoles((prevRoles) =>
      prevRoles.map((role) => {
        if (role.id !== selectedRole) return role;
        return {
          ...role,
          permissions: {
            ...role.permissions,
            [pageId]: ["view", "create", "edit", "delete"],
          },
        };
      })
    );
  };

  const clearAllForPage = (pageId: string) => {
    setRoles((prevRoles) =>
      prevRoles.map((role) => {
        if (role.id !== selectedRole) return role;
        return {
          ...role,
          permissions: {
            ...role.permissions,
            [pageId]: [],
          },
        };
      })
    );
  };

  return (
    <MainLayout title="User Permissions" description="Manage role-based access">
      <PageHeader
        title="User Permissions"
        description="Configure page-wise access permissions for user roles"
        extra={
          <Button onClick={handleSavePermissions}>
            <Save className="h-4 w-4 mr-2" />
            Save Changes
          </Button>
        }
      />

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        {/* Roles List */}
        <div className="lg:col-span-1">
          <Card>
            <CardHeader className="pb-3">
              <div className="flex items-center justify-between">
                <CardTitle className="text-lg">Roles</CardTitle>
                <Dialog open={isAddRoleOpen} onOpenChange={setIsAddRoleOpen}>
                  <DialogTrigger asChild>
                    <Button size="sm" variant="outline">
                      <Plus className="h-4 w-4" />
                    </Button>
                  </DialogTrigger>
                  <DialogContent>
                    <DialogHeader>
                      <DialogTitle>Create New Role</DialogTitle>
                      <DialogDescription>
                        Add a new user role with custom permissions
                      </DialogDescription>
                    </DialogHeader>
                    <div className="space-y-4 py-4">
                      <div className="space-y-2">
                        <label className="text-sm font-medium">Role Name</label>
                        <Input
                          placeholder="e.g., Supervisor"
                          value={newRoleName}
                          onChange={(e) => setNewRoleName(e.target.value)}
                        />
                      </div>
                      <div className="space-y-2">
                        <label className="text-sm font-medium">Description</label>
                        <Input
                          placeholder="Brief description of this role"
                          value={newRoleDescription}
                          onChange={(e) => setNewRoleDescription(e.target.value)}
                        />
                      </div>
                    </div>
                    <DialogFooter>
                      <Button variant="outline" onClick={() => setIsAddRoleOpen(false)}>
                        Cancel
                      </Button>
                      <Button onClick={handleAddRole}>
                        <UserPlus className="h-4 w-4 mr-2" />
                        Create Role
                      </Button>
                    </DialogFooter>
                  </DialogContent>
                </Dialog>
              </div>
            </CardHeader>
            <CardContent className="space-y-2">
              {rolesWithCounts.map((role) => (
                <button
                  key={`${role.id}-${role.name}`}
                  onClick={() => setSelectedRole(role.id)}
                  className={`w-full text-left p-3 rounded-lg transition-colors ${
                    selectedRole === role.id
                      ? "bg-primary text-primary-foreground"
                      : "hover:bg-muted"
                  }`}
                >
                  <div className="flex items-center justify-between">
                    <span className="font-medium">{role.name}</span>
                    <Badge variant="secondary" className={selectedRole === role.id ? "bg-primary-foreground/20 text-primary-foreground" : ""}>
                      <Users className="h-3 w-3 mr-1" />
                      {role.usersCount}
                    </Badge>
                  </div>
                  <p className={`text-xs mt-1 ${selectedRole === role.id ? "text-primary-foreground/80" : "text-muted-foreground"}`}>
                    {role.description}
                  </p>
                </button>
              ))}
            </CardContent>
          </Card>
        </div>

        {/* Permissions Matrix */}
        <div className="lg:col-span-3">
          <Card>
            <CardHeader>
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <Shield className="h-5 w-5 text-primary" />
                  <div>
                    <CardTitle className="text-lg">
                      {currentRole?.name} Permissions
                    </CardTitle>
                    <CardDescription>{currentRole?.description}</CardDescription>
                  </div>
                </div>
                <div className="relative w-64">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                  <Input
                    placeholder="Search pages..."
                    value={searchQuery}
                    onChange={(e) => pageSearch?.setTerm(e.target.value)}
                    className="pl-10"
                  />
                </div>
              </div>
            </CardHeader>
            <CardContent>
              <div className="rounded-md border">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead className="w-[200px]">Page / Module</TableHead>
                      <TableHead className="text-center w-[100px]">
                        <div className="flex items-center justify-center gap-1">
                          <Eye className="h-4 w-4" />
                          View
                        </div>
                      </TableHead>
                      <TableHead className="text-center w-[100px]">
                        <div className="flex items-center justify-center gap-1">
                          <Plus className="h-4 w-4" />
                          Create
                        </div>
                      </TableHead>
                      <TableHead className="text-center w-[100px]">
                        <div className="flex items-center justify-center gap-1">
                          <Pencil className="h-4 w-4" />
                          Edit
                        </div>
                      </TableHead>
                      <TableHead className="text-center w-[100px]">
                        <div className="flex items-center justify-center gap-1">
                          <Trash2 className="h-4 w-4" />
                          Delete
                        </div>
                      </TableHead>
                      <TableHead className="w-[120px]">Actions</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {Object.entries(groupedPages).map(([category, pages]) => (
                      <Fragment key={category}>
                        <TableRow className="bg-muted/50">
                          <TableCell colSpan={6} className="font-semibold text-sm">
                            {category}
                          </TableCell>
                        </TableRow>
                        {pages.map((page) => (
                          <TableRow key={page.id}>
                            <TableCell className="font-medium">{page.name}</TableCell>
                            <TableCell className="text-center">
                              <Checkbox
                                checked={hasPermission(page.id, "view")}
                                onCheckedChange={() => togglePermission(page.id, "view")}
                              />
                            </TableCell>
                            <TableCell className="text-center">
                              <Checkbox
                                checked={hasPermission(page.id, "create")}
                                onCheckedChange={() => togglePermission(page.id, "create")}
                              />
                            </TableCell>
                            <TableCell className="text-center">
                              <Checkbox
                                checked={hasPermission(page.id, "edit")}
                                onCheckedChange={() => togglePermission(page.id, "edit")}
                              />
                            </TableCell>
                            <TableCell className="text-center">
                              <Checkbox
                                checked={hasPermission(page.id, "delete")}
                                onCheckedChange={() => togglePermission(page.id, "delete")}
                              />
                            </TableCell>
                            <TableCell>
                              <div className="flex gap-1">
                                <Button
                                  variant="ghost"
                                  size="sm"
                                  onClick={() => selectAllForPage(page.id)}
                                  className="text-xs h-7 px-2"
                                >
                                  All
                                </Button>
                                <Button
                                  variant="ghost"
                                  size="sm"
                                  onClick={() => clearAllForPage(page.id)}
                                  className="text-xs h-7 px-2"
                                >
                                  None
                                </Button>
                              </div>
                            </TableCell>
                          </TableRow>
                        ))}
                      </Fragment>
                    ))}
                  </TableBody>
                </Table>
              </div>

              {/* Legend */}
              <div className="mt-4 flex items-center gap-6 text-sm text-muted-foreground">
                <div className="flex items-center gap-2">
                  <Eye className="h-4 w-4" />
                  <span>View - Can see the page and data</span>
                </div>
                <div className="flex items-center gap-2">
                  <Plus className="h-4 w-4" />
                  <span>Create - Can add new records</span>
                </div>
                <div className="flex items-center gap-2">
                  <Pencil className="h-4 w-4" />
                  <span>Edit - Can modify existing records</span>
                </div>
                <div className="flex items-center gap-2">
                  <Trash2 className="h-4 w-4" />
                  <span>Delete - Can remove records</span>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>
      </div>
    </MainLayout>
  );
}

import { useState } from "react";
import { MainLayout } from "@/components/layout/MainLayout";
import { PageHeader } from "@/components/shared/PageHeader";
import { DataTable } from "@/components/shared/DataTable";
import { Button } from "@/components/ui/button";
import { MoreHorizontal, Eye, Pencil, Trash2, Mail, Phone, Loader2 } from "lucide-react";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Vendor } from "@/types";
import { toast } from "sonner";
import { useVendors, useCreateVendor, useUpdateVendor, useDeleteVendor } from "@/hooks/useVendors";
import { VendorFormModal } from "@/components/forms/VendorFormModal";

export default function Vendors() {
  const { data: vendors, isLoading } = useVendors();
  const createVendor = useCreateVendor();
  const updateVendor = useUpdateVendor();
  const deleteVendor = useDeleteVendor();

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingVendor, setEditingVendor] = useState<Vendor | null>(null);

  const vendorList = vendors || [];

  const columns = [
    { key: "name", label: "Vendor Name", render: (value: string, row: Vendor) => (
      <div><p className="font-medium">{value}</p><p className="text-xs text-muted-foreground">{row.contact_info}</p></div>
    )},
    { key: "email", label: "Email", render: (value: string) => <a href={`mailto:${value}`} className="text-primary hover:underline">{value}</a> },
    { key: "phone", label: "Phone", render: (value: string) => <span className="text-muted-foreground">{value}</span> },
    { key: "address", label: "Address", render: (value: string) => <span className="text-sm text-muted-foreground truncate max-w-[200px] block">{value}</span> },
  ];

  const handleAddVendor = () => {
    setEditingVendor(null);
    setIsModalOpen(true);
  };

  const handleEdit = (vendor: Vendor) => {
    setEditingVendor(vendor);
    setIsModalOpen(true);
  };

  const handleSubmit = async (data: any) => {
    if (editingVendor) {
      await updateVendor.mutateAsync({ id: editingVendor.id, data });
    } else {
      await createVendor.mutateAsync(data);
    }
  };

  const handleDelete = (id: string) => {
    if (confirm("Are you sure you want to delete this vendor?")) {
      deleteVendor.mutate(id);
    }
  };

  const actions = (row: Vendor) => (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button variant="ghost" size="icon" className="h-8 w-8"><MoreHorizontal className="h-4 w-4" /></Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end">
        <DropdownMenuItem onClick={() => toast.info("View details would open")}>
          <Eye className="h-4 w-4 mr-2" /> View Details
        </DropdownMenuItem>
        <DropdownMenuItem onClick={() => handleEdit(row)}>
          <Pencil className="h-4 w-4 mr-2" /> Edit
        </DropdownMenuItem>
        <DropdownMenuSeparator />
        <DropdownMenuItem onClick={() => window.location.href = `mailto:${row.email}`}>
          <Mail className="h-4 w-4 mr-2" /> Send Email
        </DropdownMenuItem>
        <DropdownMenuItem onClick={() => window.location.href = `tel:${row.phone}`}>
          <Phone className="h-4 w-4 mr-2" /> Call
        </DropdownMenuItem>
        <DropdownMenuSeparator />
        <DropdownMenuItem className="text-destructive" onClick={() => handleDelete(row.id)}>
          <Trash2 className="h-4 w-4 mr-2" /> Delete
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );

  if (isLoading) {
    return (
      <MainLayout title="Vendors" description="Manage your suppliers">
        <div className="flex items-center justify-center h-64">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      </MainLayout>
    );
  }

  return (
    <MainLayout title="Vendors" description="Manage your suppliers">
      <PageHeader
        title="Vendors"
        description="View and manage asset suppliers and vendors"
        action={{ label: "Add Vendor", onClick: handleAddVendor }}
      />

      <DataTable columns={columns} data={vendorList} searchPlaceholder="Search vendors..." actions={actions} />

      <VendorFormModal
        open={isModalOpen}
        onOpenChange={setIsModalOpen}
        vendor={editingVendor}
        onSubmit={handleSubmit}
      />
    </MainLayout>
  );
}

import { useEffect, useMemo } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { MainLayout } from '@/components/layout/MainLayout';
import { PageHeader } from '@/components/shared/PageHeader';
import { DataTable } from '@/components/shared/DataTable';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Loader2 } from 'lucide-react';
import { useAuth } from '@/contexts/AuthContext';
import { useConsumableMode } from '@/hooks/useConsumableMode';
import { ConsumableModeToggle } from '@/components/consumables/ConsumableModeToggle';
import { filterItemsByMode, filterLocationsByMode } from '@/lib/consumableMode';
import { useConsumableItems } from '@/hooks/useConsumableItems';
import { useOffices } from '@/hooks/useOffices';
import { useEmployees } from '@/hooks/useEmployees';
import { useOfficeSubLocations } from '@/hooks/useOfficeSubLocations';
import { useConsumableLots } from '@/hooks/useConsumableLots';
import {
  useConsumableBalances,
  useConsumableLedger,
  useTransferConsumables,
} from '@/hooks/useConsumableInventory';
import { useConsumableUnits } from '@/hooks/useConsumableUnits';
import { getCompatibleUnits } from '@/lib/unitUtils';
import type { ConsumableItem, ConsumableInventoryTransaction } from '@/types';

const FEFO_VALUE = '__fefo__';
const assigneeTypeSchema = z.enum(['EMPLOYEE', 'SUB_LOCATION']);

const assignmentSchema = z.object({
  sourceOfficeId: z.string().min(1, 'Source office is required'),
  assigneeType: assigneeTypeSchema,
  assigneeId: z.string().min(1, 'Assignee is required'),
  itemId: z.string().min(1, 'Item is required'),
  lotId: z.string().optional(),
  qty: z.coerce.number().positive('Quantity must be greater than zero'),
  uom: z.string().min(1, 'Unit is required'),
  reference: z.string().optional(),
  notes: z.string().optional(),
});

type AssignmentFormData = z.infer<typeof assignmentSchema>;
type AssigneeType = z.infer<typeof assigneeTypeSchema>;

type AssigneeOption = {
  id: string;
  label: string;
  type: AssigneeType;
};

function asId<T extends { id?: string; _id?: string }>(row: T): string {
  return String(row.id || row._id || '');
}

export default function ConsumableAssignments() {
  const { role, locationId } = useAuth();
  const { mode, setMode } = useConsumableMode();
  const { data: items } = useConsumableItems();
  const { data: locations } = useOffices({
    capability: mode === 'chemicals' ? 'chemicals' : 'consumables',
  });
  const { data: employees = [] } = useEmployees();
  const { data: lots } = useConsumableLots();
  const { data: units } = useConsumableUnits();
  const transferMutation = useTransferConsumables();

  const form = useForm<AssignmentFormData>({
    resolver: zodResolver(assignmentSchema),
    defaultValues: {
      sourceOfficeId: locationId || '',
      assigneeType: 'EMPLOYEE',
      assigneeId: '',
      itemId: '',
      lotId: FEFO_VALUE,
      qty: 0,
      uom: '',
      reference: '',
      notes: '',
    },
  });

  const filteredLocations = useMemo(() => filterLocationsByMode(locations || [], mode), [locations, mode]);
  const modeFilteredItems = useMemo(() => filterItemsByMode(items || [], mode), [items, mode]);
  const unitList = useMemo(() => units || [], [units]);

  const sourceOfficeId = form.watch('sourceOfficeId');
  const assigneeType = form.watch('assigneeType');
  const assigneeId = form.watch('assigneeId');
  const itemId = form.watch('itemId');
  const lotId = form.watch('lotId');
  const uom = form.watch('uom');

  const { data: sections = [] } = useOfficeSubLocations({ officeId: sourceOfficeId || undefined });

  useEffect(() => {
    if (role !== 'org_admin') {
      if (locationId && form.getValues('sourceOfficeId') !== locationId) {
        form.setValue('sourceOfficeId', locationId);
      }
      return;
    }
    if (!filteredLocations.length) return;
    const current = form.getValues('sourceOfficeId');
    if (!current || !filteredLocations.some((office) => office.id === current)) {
      form.setValue('sourceOfficeId', filteredLocations[0].id);
    }
  }, [role, locationId, filteredLocations, form]);

  const officeBalancesFilters = useMemo(() => {
    if (!sourceOfficeId) return undefined;
    return {
      holderType: 'OFFICE' as const,
      holderId: sourceOfficeId,
    };
  }, [sourceOfficeId]);
  const { data: officeBalances = [] } = useConsumableBalances(officeBalancesFilters);

  const availableByItemId = useMemo(() => {
    const map = new Map<string, number>();
    officeBalances.forEach((balance) => {
      map.set(
        balance.consumable_item_id,
        (map.get(balance.consumable_item_id) || 0) + (balance.qty_on_hand_base || 0)
      );
    });
    return map;
  }, [officeBalances]);

  const filteredItems = useMemo(
    () => modeFilteredItems.filter((item) => (availableByItemId.get(item.id) || 0) > 0),
    [modeFilteredItems, availableByItemId]
  );

  const selectedItem: ConsumableItem | undefined = useMemo(
    () => filteredItems.find((item) => item.id === itemId),
    [filteredItems, itemId]
  );

  const compatibleUnits = useMemo(() => {
    if (!selectedItem) return [] as string[];
    const resolved = getCompatibleUnits(selectedItem.base_uom, unitList);
    if (!resolved.length) return [selectedItem.base_uom];
    if (!resolved.includes(selectedItem.base_uom)) return [selectedItem.base_uom, ...resolved];
    return resolved;
  }, [selectedItem, unitList]);

  useEffect(() => {
    const currentItem = form.getValues('itemId');
    if (currentItem && !filteredItems.some((item) => item.id === currentItem)) {
      form.setValue('itemId', '');
      form.setValue('lotId', FEFO_VALUE);
      form.setValue('uom', '');
    }
  }, [filteredItems, form]);

  useEffect(() => {
    if (selectedItem && !form.getValues('uom')) {
      form.setValue('uom', selectedItem.base_uom);
    }
  }, [selectedItem, form]);

  const assigneeOptions = useMemo<AssigneeOption[]>(() => {
    if (!sourceOfficeId) return [];
    if (assigneeType === 'EMPLOYEE') {
      return employees
        .filter(
          (employee) =>
            employee.is_active !== false &&
            employee.location_id &&
            String(employee.location_id) === sourceOfficeId
        )
        .map((employee) => ({
          id: asId(employee),
          type: 'EMPLOYEE' as const,
          label: `${employee.first_name || ''} ${employee.last_name || ''}`.trim() || employee.email,
        }))
        .filter((option) => option.id);
    }
    return sections.map((section) => ({
      id: asId(section),
      type: 'SUB_LOCATION' as const,
      label: section.name,
    })).filter((option) => option.id);
  }, [assigneeType, sourceOfficeId, employees, sections]);

  useEffect(() => {
    if (!assigneeOptions.length) {
      form.setValue('assigneeId', '');
      return;
    }
    const current = form.getValues('assigneeId');
    if (!current || !assigneeOptions.some((option) => option.id === current)) {
      form.setValue('assigneeId', assigneeOptions[0].id);
    }
  }, [assigneeOptions, form]);

  const availableQty = itemId ? availableByItemId.get(itemId) || 0 : 0;

  const handleSubmit = async (data: AssignmentFormData) => {
    if (!filteredLocations.some((office) => office.id === data.sourceOfficeId)) {
      form.setError('sourceOfficeId', { message: 'Selected source office is invalid.' });
      return;
    }
    if (!assigneeOptions.some((option) => option.id === data.assigneeId)) {
      form.setError('assigneeId', { message: 'Selected assignee is invalid or no longer available.' });
      return;
    }
    if (!filteredItems.some((item) => item.id === data.itemId)) {
      form.setError('itemId', { message: 'Selected item is invalid or no longer available.' });
      return;
    }

    if (availableQty > 0 && data.qty > availableQty) {
      form.setError('qty', { message: `Available stock is ${availableQty} ${selectedItem?.base_uom || ''}` });
      return;
    }

    await transferMutation.mutateAsync({
      fromHolderType: 'OFFICE',
      fromHolderId: data.sourceOfficeId,
      toHolderType: data.assigneeType,
      toHolderId: data.assigneeId,
      itemId: data.itemId,
      lotId: data.lotId && data.lotId !== FEFO_VALUE ? data.lotId : undefined,
      qty: data.qty,
      uom: data.uom,
      reference: data.reference || undefined,
      notes: data.notes || undefined,
    });

    form.reset({
      sourceOfficeId: data.sourceOfficeId,
      assigneeType: data.assigneeType,
      assigneeId: data.assigneeId,
      itemId: '',
      lotId: FEFO_VALUE,
      qty: 0,
      uom: '',
      reference: '',
      notes: '',
    });
  };

  const ledgerFilters = useMemo(
    () => ({
      txType: 'TRANSFER',
      holderType: 'OFFICE' as const,
      holderId: sourceOfficeId || undefined,
    }),
    [sourceOfficeId]
  );
  const { data: ledger = [] } = useConsumableLedger(ledgerFilters);

  const itemMap = useMemo(() => new Map((items || []).map((item) => [item.id, item])), [items]);
  const employeeMap = useMemo(
    () =>
      new Map(
        employees.map((employee) => [
          asId(employee),
          `${employee.first_name || ''} ${employee.last_name || ''}`.trim() || employee.email || asId(employee),
        ])
      ),
    [employees]
  );
  const sectionMap = useMemo(
    () => new Map(sections.map((section) => [asId(section), section.name])),
    [sections]
  );

  const assignmentHistory = useMemo(
    () =>
      ledger
        .filter(
          (entry) =>
            entry.tx_type === 'TRANSFER' &&
            entry.from_holder_type === 'OFFICE' &&
            (entry.to_holder_type === 'EMPLOYEE' || entry.to_holder_type === 'SUB_LOCATION')
        )
        .filter((entry) => {
          const item = itemMap.get(entry.consumable_item_id);
          if (!item) return false;
          const isChemical = item.is_chemical === true;
          return mode === 'chemicals' ? isChemical : !isChemical;
        }),
    [ledger, itemMap, mode]
  );

  const columns = [
    {
      key: 'tx_time',
      label: 'Date',
      render: (value: string) => new Date(value).toLocaleString(),
    },
    {
      key: 'consumable_item_id',
      label: 'Item',
      render: (value: string) => itemMap.get(value)?.name || 'Unknown',
    },
    {
      key: 'to_holder_type',
      label: 'Assigned To',
      render: (_: string, row: ConsumableInventoryTransaction) => {
        if (row.to_holder_type === 'EMPLOYEE') {
          return row.to_holder_id ? `${employeeMap.get(row.to_holder_id) || 'Unknown Employee'} (Employee)` : 'Employee';
        }
        if (row.to_holder_type === 'SUB_LOCATION') {
          return row.to_holder_id ? `${sectionMap.get(row.to_holder_id) || 'Unknown Section'} (Section)` : 'Section';
        }
        return 'N/A';
      },
    },
    {
      key: 'entered_qty',
      label: 'Qty',
      render: (_: number, row: ConsumableInventoryTransaction) => `${row.entered_qty} ${row.entered_uom}`,
    },
    {
      key: 'reference',
      label: 'Reference',
      render: (value: string | null) => value || '-',
    },
  ];

  return (
    <MainLayout title="Consumable Assignments" description="Assign consumables to employees and sections">
      <PageHeader
        title="Consumable Assignments"
        description="Assign stock from office storage to employees or sections/rooms"
        extra={<ConsumableModeToggle mode={mode} onChange={setMode} />}
      />

      <Card className="mb-6">
        <CardContent className="pt-6">
          <form onSubmit={form.handleSubmit(handleSubmit)} className="space-y-6">
            <div className="grid grid-cols-3 gap-4">
              <div className="space-y-2">
                <Label>Source Office *</Label>
                {role === 'org_admin' ? (
                  <Select value={sourceOfficeId} onValueChange={(value) => form.setValue('sourceOfficeId', value)}>
                    <SelectTrigger><SelectValue placeholder="Select office" /></SelectTrigger>
                    <SelectContent>
                      {filteredLocations.map((office) => (
                        <SelectItem key={office.id} value={office.id}>{office.name}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                ) : (
                  <div className="rounded-md border bg-muted/30 px-3 py-2 text-sm">
                    {filteredLocations.find((office) => office.id === sourceOfficeId)?.name || 'Assigned Office'}
                  </div>
                )}
              </div>

              <div className="space-y-2">
                <Label>Assignee Type *</Label>
                <Select
                  value={assigneeType}
                  onValueChange={(value) => {
                    form.setValue('assigneeType', value as AssigneeType);
                    form.setValue('assigneeId', '');
                  }}
                >
                  <SelectTrigger><SelectValue placeholder="Select type" /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="EMPLOYEE">Employee</SelectItem>
                    <SelectItem value="SUB_LOCATION">Section / Room</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label>Assignee *</Label>
                <Select value={assigneeId} onValueChange={(value) => form.setValue('assigneeId', value)}>
                  <SelectTrigger><SelectValue placeholder="Select assignee" /></SelectTrigger>
                  <SelectContent>
                    {assigneeOptions.map((option) => (
                      <SelectItem key={`${option.type}:${option.id}`} value={option.id}>{option.label}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                {form.formState.errors.assigneeId && (
                  <p className="text-sm text-destructive">{form.formState.errors.assigneeId.message}</p>
                )}
              </div>
            </div>

            <div className="grid grid-cols-4 gap-4">
              <div className="space-y-2">
                <Label>Item *</Label>
                <Select value={itemId} onValueChange={(value) => form.setValue('itemId', value)}>
                  <SelectTrigger><SelectValue placeholder="Select item" /></SelectTrigger>
                  <SelectContent>
                    {filteredItems.map((item) => (
                      <SelectItem key={item.id} value={item.id}>{item.name}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                {form.formState.errors.itemId && (
                  <p className="text-sm text-destructive">{form.formState.errors.itemId.message}</p>
                )}
              </div>

              <div className="space-y-2">
                <Label>Lot (optional)</Label>
                <Select value={lotId || FEFO_VALUE} onValueChange={(value) => form.setValue('lotId', value)}>
                  <SelectTrigger><SelectValue placeholder="FEFO default" /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value={FEFO_VALUE}>FEFO default</SelectItem>
                    {(lots || [])
                      .filter((lot) => !itemId || lot.consumable_id === itemId)
                      .map((lot) => (
                        <SelectItem key={lot.id} value={lot.id}>{lot.batch_no}</SelectItem>
                      ))}
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label htmlFor="qty">Quantity *</Label>
                <Input id="qty" type="number" min={0} step="0.01" {...form.register('qty')} />
                {form.formState.errors.qty && (
                  <p className="text-sm text-destructive">{form.formState.errors.qty.message}</p>
                )}
              </div>

              <div className="space-y-2">
                <Label>UoM *</Label>
                <Select value={uom} onValueChange={(value) => form.setValue('uom', value)}>
                  <SelectTrigger><SelectValue placeholder="Select unit" /></SelectTrigger>
                  <SelectContent>
                    {compatibleUnits.map((unit) => (
                      <SelectItem key={unit} value={unit}>{unit}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                {form.formState.errors.uom && (
                  <p className="text-sm text-destructive">{form.formState.errors.uom.message}</p>
                )}
              </div>
            </div>

            <div className="grid grid-cols-3 gap-4">
              <div className="space-y-2">
                <Label>Available</Label>
                <div className="rounded-md border bg-muted/30 px-3 py-2 text-sm">
                  {availableQty} {selectedItem?.base_uom || ''}
                </div>
              </div>

              <div className="space-y-2">
                <Label htmlFor="reference">Reference</Label>
                <Input id="reference" {...form.register('reference')} />
              </div>

              <div className="space-y-2">
                <Label htmlFor="notes">Notes</Label>
                <Input id="notes" {...form.register('notes')} />
              </div>
            </div>

            <div className="flex justify-end">
              <Button type="submit" disabled={transferMutation.isPending}>
                {transferMutation.isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                Assign
              </Button>
            </div>
          </form>
        </CardContent>
      </Card>

      <Card>
        <CardContent className="pt-6">
          <h3 className="mb-4 text-lg font-semibold">Recent Assignments</h3>
          <DataTable
            columns={columns}
            data={assignmentHistory as any}
            searchPlaceholder="Search assignments..."
          />
        </CardContent>
      </Card>
    </MainLayout>
  );
}

import { useMemo, useState } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { MainLayout } from '@/components/layout/MainLayout';
import { PageHeader } from '@/components/shared/PageHeader';
import { DataTable } from '@/components/shared/DataTable';
import { Button } from '@/components/ui/button';
import { Card, CardContent } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { Loader2, MoreHorizontal, Pencil, Trash2 } from 'lucide-react';
import type { ConsumableContainer } from '@/types';
import { useConsumableLots } from '@/hooks/useConsumableLots';
import { useConsumableItems } from '@/hooks/useConsumableItems';
import { useOffices } from '@/hooks/useOffices';
import {
  useConsumableContainers,
  useCreateConsumableContainer,
  useDeleteConsumableContainer,
  useUpdateConsumableContainer,
} from '@/hooks/useConsumableContainers';
import { useAuth } from '@/contexts/AuthContext';

const ALL_VALUE = '__all__';

const containerSchema = z.object({
  lotId: z.string().min(1, 'Lot is required'),
  containerCode: z.string().min(1, 'Container code is required'),
  initialQtyBase: z.coerce.number().min(0, 'Initial qty must be 0 or greater'),
  currentQtyBase: z.coerce.number().min(0, 'Current qty must be 0 or greater'),
  currentLocationId: z.string().min(1, 'Location is required'),
  status: z.enum(['IN_STOCK', 'EMPTY', 'DISPOSED', 'LOST']),
  openedDate: z.string().optional(),
});

type ContainerFormData = z.infer<typeof containerSchema>;

function ContainerFormModal(props: {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  editingContainer: ConsumableContainer | null;
  lots: Array<{ id: string; batch_no: string }>;
  locations: Array<{ id: string; name: string }>;
  onSubmit: (data: ContainerFormData) => Promise<void>;
}) {
  const { open, onOpenChange, editingContainer, lots, locations, onSubmit } = props;
  const [isSubmitting, setIsSubmitting] = useState(false);

  const form = useForm<ContainerFormData>({
    resolver: zodResolver(containerSchema),
    values: {
      lotId: editingContainer?.lot_id || '',
      containerCode: editingContainer?.container_code || '',
      initialQtyBase: editingContainer?.initial_qty_base || 0,
      currentQtyBase: editingContainer?.current_qty_base || 0,
      currentLocationId: editingContainer?.current_location_id || '',
      status: (editingContainer?.status || 'IN_STOCK') as 'IN_STOCK' | 'EMPTY' | 'DISPOSED' | 'LOST',
      openedDate: editingContainer?.opened_date || '',
    },
  });

  const submit = async (data: ContainerFormData) => {
    setIsSubmitting(true);
    try {
      await onSubmit(data);
      onOpenChange(false);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[560px] max-h-[85vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>{editingContainer ? 'Edit Container' : 'Add Container'}</DialogTitle>
          <DialogDescription>Manage tracked consumable containers.</DialogDescription>
        </DialogHeader>
        <form onSubmit={form.handleSubmit(submit)} className="space-y-4">
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label>Lot *</Label>
              <Select value={form.watch('lotId')} onValueChange={(value) => form.setValue('lotId', value)}>
                <SelectTrigger><SelectValue placeholder="Select lot" /></SelectTrigger>
                <SelectContent>
                  {lots.map((lot) => (
                    <SelectItem key={lot.id} value={lot.id}>{lot.batch_no}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
              {form.formState.errors.lotId && (
                <p className="text-sm text-destructive">{form.formState.errors.lotId.message}</p>
              )}
            </div>
            <div className="space-y-2">
              <Label htmlFor="containerCode">Container Code *</Label>
              <Input id="containerCode" {...form.register('containerCode')} />
              {form.formState.errors.containerCode && (
                <p className="text-sm text-destructive">{form.formState.errors.containerCode.message}</p>
              )}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="initialQtyBase">Initial Qty (base) *</Label>
              <Input id="initialQtyBase" type="number" min={0} step="0.01" {...form.register('initialQtyBase')} />
            </div>
            <div className="space-y-2">
              <Label htmlFor="currentQtyBase">Current Qty (base) *</Label>
              <Input id="currentQtyBase" type="number" min={0} step="0.01" {...form.register('currentQtyBase')} />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label>Location *</Label>
              <Select value={form.watch('currentLocationId')} onValueChange={(value) => form.setValue('currentLocationId', value)}>
                <SelectTrigger><SelectValue placeholder="Select location" /></SelectTrigger>
                <SelectContent>
                  {locations.map((location) => (
                    <SelectItem key={location.id} value={location.id}>{location.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
              {form.formState.errors.currentLocationId && (
                <p className="text-sm text-destructive">{form.formState.errors.currentLocationId.message}</p>
              )}
            </div>
            <div className="space-y-2">
              <Label>Status *</Label>
              <Select
                value={form.watch('status')}
                onValueChange={(value) =>
                  form.setValue('status', value as 'IN_STOCK' | 'EMPTY' | 'DISPOSED' | 'LOST')
                }
              >
                <SelectTrigger><SelectValue placeholder="Select status" /></SelectTrigger>
                <SelectContent>
                  <SelectItem value="IN_STOCK">In Stock</SelectItem>
                  <SelectItem value="EMPTY">Empty</SelectItem>
                  <SelectItem value="DISPOSED">Disposed</SelectItem>
                  <SelectItem value="LOST">Lost</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>

          <div className="space-y-2">
            <Label htmlFor="openedDate">Opened Date</Label>
            <Input id="openedDate" type="date" {...form.register('openedDate')} />
          </div>

          <DialogFooter>
            <Button type="button" variant="outline" onClick={() => onOpenChange(false)} disabled={isSubmitting}>
              Cancel
            </Button>
            <Button type="submit" disabled={isSubmitting}>
              {isSubmitting && <Loader2 className="h-4 w-4 mr-2 animate-spin" />}
              {editingContainer ? 'Update' : 'Create'}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

export default function ConsumableContainers() {
  const { role, isOrgAdmin } = useAuth();
  const [selectedLocationId, setSelectedLocationId] = useState(ALL_VALUE);
  const [selectedStatus, setSelectedStatus] = useState(ALL_VALUE);
  const [formOpen, setFormOpen] = useState(false);
  const [editingContainer, setEditingContainer] = useState<ConsumableContainer | null>(null);

  const { data: lots = [] } = useConsumableLots();
  const { data: items = [] } = useConsumableItems();
  const { data: locations = [] } = useOffices();
  const filters = useMemo(() => {
    const value: { locationId?: string; status?: string } = {};
    if (selectedLocationId !== ALL_VALUE) value.locationId = selectedLocationId;
    if (selectedStatus !== ALL_VALUE) value.status = selectedStatus;
    return value;
  }, [selectedLocationId, selectedStatus]);
  const { data: containers = [], isLoading } = useConsumableContainers(filters);

  const createContainer = useCreateConsumableContainer();
  const updateContainer = useUpdateConsumableContainer();
  const deleteContainer = useDeleteConsumableContainer();
  const canCreateOrDelete = isOrgAdmin || role === 'caretaker';
  const canUpdate = canCreateOrDelete || role === 'office_head';

  const lotMap = useMemo(() => new Map(lots.map((lot) => [lot.id, lot])), [lots]);
  const itemMap = useMemo(() => new Map(items.map((item) => [item.id, item])), [items]);
  const locationMap = useMemo(() => new Map(locations.map((location) => [location.id, location.name])), [locations]);

  const columns = [
    { key: 'container_code', label: 'Container' },
    {
      key: 'lot_id',
      label: 'Lot',
      render: (value: string) => lotMap.get(value)?.batch_no || 'Unknown',
    },
    {
      key: 'lot_id_item',
      label: 'Item',
      render: (_: unknown, row: ConsumableContainer) => {
        const lot = lotMap.get(row.lot_id);
        if (!lot) return 'Unknown';
        return itemMap.get(lot.consumable_id)?.name || 'Unknown';
      },
    },
    {
      key: 'current_qty_base',
      label: 'Current Qty',
      render: (value: number) => value,
    },
    {
      key: 'current_location_id',
      label: 'Location',
      render: (value: string) => locationMap.get(value) || 'Unknown',
    },
    { key: 'status', label: 'Status' },
  ];

  const actions = (row: ConsumableContainer) => (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button variant="ghost" size="icon" className="h-8 w-8">
          <MoreHorizontal className="h-4 w-4" />
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end">
        {canUpdate && (
          <DropdownMenuItem
            onClick={() => {
              setEditingContainer(row);
              setFormOpen(true);
            }}
          >
            <Pencil className="h-4 w-4 mr-2" /> Edit
          </DropdownMenuItem>
        )}
        {canCreateOrDelete && (
          <DropdownMenuItem
            className="text-destructive"
            onClick={() => {
              if (confirm(`Delete container "${row.container_code}"?`)) {
                deleteContainer.mutate(row.id);
              }
            }}
          >
            <Trash2 className="h-4 w-4 mr-2" /> Delete
          </DropdownMenuItem>
        )}
      </DropdownMenuContent>
    </DropdownMenu>
  );

  const handleSubmit = async (data: ContainerFormData) => {
    if (editingContainer) {
      await updateContainer.mutateAsync({
        id: editingContainer.id,
        data: {
          lotId: data.lotId,
          containerCode: data.containerCode,
          initialQtyBase: data.initialQtyBase,
          currentQtyBase: data.currentQtyBase,
          currentLocationId: data.currentLocationId,
          status: data.status,
          openedDate: data.openedDate || undefined,
        },
      });
      return;
    }

    await createContainer.mutateAsync({
      lotId: data.lotId,
      containerCode: data.containerCode,
      initialQtyBase: data.initialQtyBase,
      currentQtyBase: data.currentQtyBase,
      currentLocationId: data.currentLocationId,
      status: data.status,
      openedDate: data.openedDate || undefined,
    });
  };

  return (
    <MainLayout title="Consumable Containers" description="Manage tracked containers">
      <PageHeader
        title="Containers"
        description="Create, update, and remove tracked lot containers"
        action={
          canCreateOrDelete
            ? {
                label: 'Add Container',
                onClick: () => {
                  setEditingContainer(null);
                  setFormOpen(true);
                },
              }
            : undefined
        }
      />

      <Card className="mb-6">
        <CardContent className="pt-6">
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label>Location</Label>
              <Select value={selectedLocationId} onValueChange={setSelectedLocationId}>
                <SelectTrigger><SelectValue placeholder="All locations" /></SelectTrigger>
                <SelectContent>
                  <SelectItem value={ALL_VALUE}>All locations</SelectItem>
                  {locations.map((location) => (
                    <SelectItem key={location.id} value={location.id}>{location.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label>Status</Label>
              <Select value={selectedStatus} onValueChange={setSelectedStatus}>
                <SelectTrigger><SelectValue placeholder="All statuses" /></SelectTrigger>
                <SelectContent>
                  <SelectItem value={ALL_VALUE}>All statuses</SelectItem>
                  <SelectItem value="IN_STOCK">In Stock</SelectItem>
                  <SelectItem value="EMPTY">Empty</SelectItem>
                  <SelectItem value="DISPOSED">Disposed</SelectItem>
                  <SelectItem value="LOST">Lost</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>
        </CardContent>
      </Card>

      {isLoading ? (
        <div className="flex items-center justify-center h-56">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      ) : (
        <DataTable
          columns={columns}
          data={containers as any[]}
          searchPlaceholder="Search containers..."
          actions={canUpdate || canCreateOrDelete ? actions : undefined}
        />
      )}

      <ContainerFormModal
        open={formOpen}
        onOpenChange={setFormOpen}
        editingContainer={editingContainer}
        lots={lots}
        locations={locations}
        onSubmit={handleSubmit}
      />
    </MainLayout>
  );
}

import { useEffect, useState } from 'react';
import { MainLayout } from '@/components/layout/MainLayout';
import { PageHeader } from '@/components/shared/PageHeader';
import { DataTable } from '@/components/shared/DataTable';
import { Card, CardContent } from '@/components/ui/card';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { useConsumableExpiry } from '@/hooks/useConsumableInventory';
import { useConsumableItems } from '@/hooks/useConsumableItems';
import { useOffices } from '@/hooks/useOffices';
import { useEmployees } from '@/hooks/useEmployees';
import { useOfficeSubLocations } from '@/hooks/useOfficeSubLocations';
import { useConsumableLots } from '@/hooks/useConsumableLots';
import type { ConsumableExpiryRow } from '@/types';
import { useConsumableMode } from '@/hooks/useConsumableMode';
import { filterItemsByMode, filterLocationsByMode } from '@/lib/consumableMode';
import { ConsumableModeToggle } from '@/components/consumables/ConsumableModeToggle';

export default function ConsumableExpiry() {
  const ALL_VALUE = '__all__';
  const [days, setDays] = useState(30);
  const [locationId, setLocationId] = useState(ALL_VALUE);

  const { mode, setMode } = useConsumableMode();
  const { data: items } = useConsumableItems();
  const { data: locations } = useOffices({
    capability: mode === 'chemicals' ? 'chemicals' : 'consumables',
  });
  const { data: employees = [] } = useEmployees();
  const { data: sections = [] } = useOfficeSubLocations();
  const { data: lots } = useConsumableLots();
  const { data: expiry = [] } = useConsumableExpiry(days);

  const filteredItems = filterItemsByMode(items || [], mode);
  const filteredLocations = filterLocationsByMode(locations || [], mode);
  const employeeNameMap = new Map(
    employees.map((employee) => [
      employee.id,
      `${employee.first_name || ''} ${employee.last_name || ''}`.trim() || employee.email || employee.id,
    ])
  );
  const sectionNameMap = new Map(sections.map((section) => [section.id, section.name]));
  const visibleExpiry = expiry.filter((row) => {
    if (!filteredItems.some((item) => item.id === row.itemId)) return false;
    if (locationId === ALL_VALUE) return true;
    return row.locationId === locationId;
  });

  useEffect(() => {
    if (locationId !== ALL_VALUE && !filteredLocations.some((loc) => loc.id === locationId)) {
      setLocationId(ALL_VALUE);
    }
  }, [locationId, filteredLocations, ALL_VALUE]);

  const columns = [
    {
      key: 'lotId',
      label: 'Lot',
      render: (value: string) => lots?.find((lot) => lot.id === value)?.batch_no || 'Unknown',
    },
    {
      key: 'itemId',
      label: 'Item',
      render: (value: string) => filteredItems.find((item) => item.id === value)?.name || 'Unknown',
    },
    {
      key: 'holderId',
      label: 'Holder',
      render: (_value: string, row: ConsumableExpiryRow) => {
        if (row.holderType === 'STORE') return 'Head Office Store';
        if (row.holderType === 'EMPLOYEE') {
          return row.holderId ? `${employeeNameMap.get(row.holderId) || 'Unknown Employee'} (Employee)` : 'Unknown';
        }
        if (row.holderType === 'SUB_LOCATION') {
          return row.holderId ? `${sectionNameMap.get(row.holderId) || 'Unknown Section'} (Section)` : 'Unknown';
        }
        const officeId = row.holderId || '';
        return filteredLocations.find((loc) => loc.id === officeId)?.name || 'Unknown Office';
      },
    },
    {
      key: 'expiryDate',
      label: 'Expiry Date',
      render: (value: string) => new Date(value).toLocaleDateString(),
    },
    {
      key: 'qtyOnHandBase',
      label: 'Qty (base)',
      render: (value: number, row: ConsumableExpiryRow) => {
        const item = filteredItems.find((i) => i.id === row.itemId);
        return `${value} ${item?.base_uom || ''}`;
      },
    },
  ];

  return (
    <MainLayout title="Expiry Dashboard" description="Lots nearing expiration">
      <PageHeader
        title="Expiry Dashboard"
        description="Expiring lots in the next 30/60/90 days"
        extra={<ConsumableModeToggle mode={mode} onChange={setMode} />}
      />

      <Card className="mb-6">
        <CardContent className="pt-6">
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="text-sm font-medium">Days</label>
              <Select value={String(days)} onValueChange={(v) => setDays(Number(v))}>
                <SelectTrigger><SelectValue placeholder="Select range" /></SelectTrigger>
                <SelectContent>
                  <SelectItem value="30">30 days</SelectItem>
                  <SelectItem value="60">60 days</SelectItem>
                  <SelectItem value="90">90 days</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium">Location</label>
              <Select value={locationId} onValueChange={setLocationId}>
                <SelectTrigger><SelectValue placeholder="All locations" /></SelectTrigger>
                <SelectContent>
                  <SelectItem value={ALL_VALUE}>All locations</SelectItem>
                  {filteredLocations.map((loc) => (
                    <SelectItem key={loc.id} value={loc.id}>{loc.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </div>
        </CardContent>
      </Card>

      <DataTable
        columns={columns}
        data={visibleExpiry as any}
        searchPlaceholder="Search expiring lots..."
      />
    </MainLayout>
  );
}

import { useEffect, useMemo, useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { MainLayout } from '@/components/layout/MainLayout';
import { PageHeader } from '@/components/shared/PageHeader';
import { DataTable } from '@/components/shared/DataTable';
import { Card, CardContent } from '@/components/ui/card';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Badge } from '@/components/ui/badge';
import { useConsumableBalances, useConsumableLedger } from '@/hooks/useConsumableInventory';
import { useConsumableItems } from '@/hooks/useConsumableItems';
import { useOffices } from '@/hooks/useOffices';
import { useEmployees } from '@/hooks/useEmployees';
import { useOfficeSubLocations } from '@/hooks/useOfficeSubLocations';
import { useConsumableLots } from '@/hooks/useConsumableLots';
import { consumableInventoryService } from '@/services/consumableInventoryService';
import type { ConsumableInventoryBalance } from '@/types';
import { useConsumableMode } from '@/hooks/useConsumableMode';
import { filterItemsByMode, filterLocationsByMode } from '@/lib/consumableMode';
import { ConsumableModeToggle } from '@/components/consumables/ConsumableModeToggle';
import { useAuth } from '@/contexts/AuthContext';

function asId(value: { id?: string; _id?: string }) {
  return value.id || value._id || '';
}

export default function ConsumableInventory() {
  const ALL_VALUE = '__all__';
  const STORE_FILTER = '__store__';
  const STORE_CODE = 'HEAD_OFFICE_STORE';
  const { role, locationId: assignedLocationId } = useAuth();
  const { mode, setMode } = useConsumableMode();
  const { data: items } = useConsumableItems();
  const { data: locations } = useOffices({
    capability: mode === 'chemicals' ? 'chemicals' : 'consumables',
  });
  const { data: employees = [] } = useEmployees();
  const { data: sections = [] } = useOfficeSubLocations();
  const { data: lots } = useConsumableLots();

  const [locationId, setLocationId] = useState(ALL_VALUE);
  const [itemId, setItemId] = useState(ALL_VALUE);
  const [lotId, setLotId] = useState(ALL_VALUE);
  const [holderTypeFilter, setHolderTypeFilter] = useState(ALL_VALUE);
  const [holderIdFilter, setHolderIdFilter] = useState(ALL_VALUE);

  const filteredItems = useMemo(() => filterItemsByMode(items || [], mode), [items, mode]);
  const filteredLocations = useMemo(() => filterLocationsByMode(locations || [], mode), [locations, mode]);
  const allowedItemIds = useMemo(
    () => new Set(filteredItems.map((item) => item.id)),
    [filteredItems]
  );
  const employeeNameMap = useMemo(
    () =>
      new Map(
        employees.map((employee) => [
          asId(employee),
          `${employee.first_name || ''} ${employee.last_name || ''}`.trim() || employee.email || asId(employee),
        ])
      ),
    [employees]
  );
  const employeeOfficeMap = useMemo(
    () => new Map(employees.map((employee) => [asId(employee), employee.location_id ? String(employee.location_id) : null])),
    [employees]
  );
  const sectionNameMap = useMemo(
    () => new Map(sections.map((section) => [asId(section), section.name])),
    [sections]
  );
  const sectionOfficeMap = useMemo(
    () => new Map(sections.map((section) => [asId(section), section.office_id ? String(section.office_id) : null])),
    [sections]
  );

  useEffect(() => {
    if (itemId !== ALL_VALUE && !filteredItems.some((item) => item.id === itemId)) {
      setItemId(ALL_VALUE);
      setLotId(ALL_VALUE);
    }
  }, [itemId, filteredItems, ALL_VALUE]);

  useEffect(() => {
    if (role === 'org_admin') return;
    if (!assignedLocationId) return;
    if (locationId !== assignedLocationId) {
      setLocationId(assignedLocationId);
    }
  }, [role, assignedLocationId, locationId]);

  useEffect(() => {
    if (locationId !== ALL_VALUE && locationId !== STORE_FILTER && !filteredLocations.some((loc) => loc.id === locationId)) {
      setLocationId(ALL_VALUE);
    }
  }, [locationId, filteredLocations, ALL_VALUE, STORE_FILTER]);

  useEffect(() => {
    setHolderIdFilter(ALL_VALUE);
  }, [holderTypeFilter, ALL_VALUE]);

  const holderOptions = useMemo(() => {
    if (holderTypeFilter === 'STORE') {
      return [{ id: STORE_CODE, label: 'Head Office Store' }];
    }
    if (holderTypeFilter === 'OFFICE') {
      const officeOptions =
        locationId !== ALL_VALUE && locationId !== STORE_FILTER
          ? filteredLocations.filter((location) => location.id === locationId)
          : filteredLocations;
      return officeOptions.map((location) => ({ id: location.id, label: location.name }));
    }
    if (holderTypeFilter === 'EMPLOYEE') {
      return employees
        .filter((employee) => {
          if (locationId === ALL_VALUE || locationId === STORE_FILTER) return true;
          return employee.location_id ? String(employee.location_id) === locationId : false;
        })
        .map((employee) => {
          const employeeId = asId(employee);
          return {
            id: employeeId,
            label: `${employee.first_name || ''} ${employee.last_name || ''}`.trim() || employee.email || employeeId,
          };
        })
        .filter((employee) => employee.id);
    }
    if (holderTypeFilter === 'SUB_LOCATION') {
      return sections
        .filter((section) => {
          const officeId = section.office_id ? String(section.office_id) : null;
          if (locationId === ALL_VALUE || locationId === STORE_FILTER) return true;
          return officeId === locationId;
        })
        .map((section) => ({ id: asId(section), label: section.name }))
        .filter((section) => section.id);
    }
    return [];
  }, [holderTypeFilter, locationId, filteredLocations, employees, sections, ALL_VALUE, STORE_FILTER, STORE_CODE]);

  const balanceFilters = useMemo(() => {
    const filters: any = {};
    if (holderTypeFilter !== ALL_VALUE && holderIdFilter !== ALL_VALUE) {
      filters.holderType = holderTypeFilter;
      filters.holderId = holderIdFilter;
    } else if (locationId === STORE_FILTER) {
      filters.holderType = 'STORE';
      filters.holderId = STORE_CODE;
    } else if (locationId !== ALL_VALUE) {
      filters.holderType = 'OFFICE';
      filters.holderId = locationId;
    }
    if (itemId !== ALL_VALUE) filters.itemId = itemId;
    if (lotId !== ALL_VALUE) filters.lotId = lotId;
    return Object.keys(filters).length ? filters : undefined;
  }, [holderTypeFilter, holderIdFilter, locationId, itemId, lotId, ALL_VALUE, STORE_FILTER, STORE_CODE]);

  const { data: balances = [] } = useConsumableBalances(balanceFilters);

  const { data: rollup } = useQuery({
    queryKey: ['consumableRollup', itemId !== ALL_VALUE ? itemId : 'all'],
    queryFn: () => consumableInventoryService.getRollup(itemId !== ALL_VALUE ? itemId : undefined),
    enabled: itemId !== ALL_VALUE,
  });

  const { data: ledger = [] } = useConsumableLedger(itemId !== ALL_VALUE ? { itemId } : undefined);

  const visibleBalances = useMemo(
    () =>
      (balances || []).filter((balance) => {
        if (!filteredItems.some((item) => item.id === balance.consumable_item_id)) return false;
        if (holderTypeFilter !== ALL_VALUE && holderIdFilter !== ALL_VALUE) {
          return balance.holder_type === holderTypeFilter && balance.holder_id === holderIdFilter;
        }
        if (locationId === ALL_VALUE) return true;
        if (locationId === STORE_FILTER) return balance.holder_type === 'STORE';
        if (balance.holder_type === 'OFFICE') return balance.holder_id === locationId;
        if (balance.holder_type === 'EMPLOYEE') {
          return balance.holder_id ? employeeOfficeMap.get(String(balance.holder_id)) === locationId : false;
        }
        if (balance.holder_type === 'SUB_LOCATION') {
          return balance.holder_id ? sectionOfficeMap.get(String(balance.holder_id)) === locationId : false;
        }
        return false;
      }),
    [balances, filteredItems, holderTypeFilter, holderIdFilter, locationId, ALL_VALUE, STORE_FILTER, employeeOfficeMap, sectionOfficeMap]
  );

  const columns = [
    {
      key: 'consumable_item_id',
      label: 'Item',
      render: (value: string) => filteredItems.find((item) => item.id === value)?.name || 'Unknown',
    },
    {
      key: 'holder_id',
      label: 'Holder',
      render: (_: string, row: ConsumableInventoryBalance) => {
        if (row.holder_type === 'STORE') return 'Head Office Store';
        if (row.holder_type === 'EMPLOYEE') {
          return row.holder_id ? `${employeeNameMap.get(String(row.holder_id)) || 'Unknown Employee'} (Employee)` : 'Unknown';
        }
        if (row.holder_type === 'SUB_LOCATION') {
          return row.holder_id ? `${sectionNameMap.get(String(row.holder_id)) || 'Unknown Section'} (Section)` : 'Unknown';
        }
        const officeId = row.holder_id || '';
        return filteredLocations.find((loc) => loc.id === officeId)?.name || 'Unknown Office';
      },
    },
    {
      key: 'lot_id',
      label: 'Lot',
      render: (value: string | null, row: ConsumableInventoryBalance) => {
        if (!value) {
          if ((row.lot_count || 0) > 0) {
            return `Combined (${row.lot_count} lots)`;
          }
          return 'N/A';
        }
        return lots?.find((lot) => lot.id === value)?.batch_no || 'Unknown';
      },
    },
    {
      key: 'qty_on_hand_base',
      label: 'On Hand (base)',
      render: (value: number, row: ConsumableInventoryBalance) => {
        const item = filteredItems.find((i) => i.id === row.consumable_item_id);
        return (
          <span className="font-medium">{value} {item?.base_uom || ''}</span>
        );
      },
    },
  ];

  return (
    <MainLayout title="Consumable Inventory" description="Central and lab inventory view">
      <PageHeader
        title="Inventory"
        description="View balances by location, item, and lot"
        extra={<ConsumableModeToggle mode={mode} onChange={setMode} />}
      />

      <Card className="mb-6">
        <CardContent className="pt-6">
          <div className="grid grid-cols-1 gap-4 lg:grid-cols-5">
            <div className="space-y-2">
              <label className="text-sm font-medium">Location</label>
              {role === 'org_admin' ? (
                <Select value={locationId} onValueChange={setLocationId}>
                  <SelectTrigger><SelectValue placeholder="All locations" /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value={ALL_VALUE}>All locations</SelectItem>
                    <SelectItem value={STORE_FILTER}>Head Office Store</SelectItem>
                    {filteredLocations.map((loc) => (
                      <SelectItem key={loc.id} value={loc.id}>{loc.name}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              ) : (
                <div className="rounded-md border bg-muted/30 px-3 py-2 text-sm">
                  {filteredLocations.find((loc) => loc.id === locationId)?.name || 'Assigned location'}
                </div>
              )}
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium">Item</label>
              <Select value={itemId} onValueChange={(value) => { setItemId(value); setLotId(ALL_VALUE); }}>
                <SelectTrigger><SelectValue placeholder="All items" /></SelectTrigger>
                <SelectContent>
                  <SelectItem value={ALL_VALUE}>All items</SelectItem>
                  {filteredItems.map((item) => (
                    <SelectItem key={item.id} value={item.id}>{item.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium">Lot</label>
              <Select value={lotId} onValueChange={setLotId}>
                <SelectTrigger><SelectValue placeholder="All lots" /></SelectTrigger>
                <SelectContent>
                  <SelectItem value={ALL_VALUE}>All lots</SelectItem>
                  {(lots || [])
                    .filter((lot) => {
                      if (itemId !== ALL_VALUE) return lot.consumable_id === itemId;
                      return allowedItemIds.has(lot.consumable_id);
                    })
                    .map((lot) => (
                      <SelectItem key={lot.id} value={lot.id}>{lot.batch_no}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium">Holder Type (optional)</label>
              <Select value={holderTypeFilter} onValueChange={setHolderTypeFilter}>
                <SelectTrigger><SelectValue placeholder="All holder types" /></SelectTrigger>
                <SelectContent>
                  <SelectItem value={ALL_VALUE}>All holder types</SelectItem>
                  <SelectItem value="STORE">Store</SelectItem>
                  <SelectItem value="OFFICE">Office</SelectItem>
                  <SelectItem value="SUB_LOCATION">Section / Room</SelectItem>
                  <SelectItem value="EMPLOYEE">Employee</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium">Holder (optional)</label>
              <Select
                value={holderIdFilter}
                onValueChange={setHolderIdFilter}
                disabled={holderTypeFilter === ALL_VALUE}
              >
                <SelectTrigger><SelectValue placeholder="All holders" /></SelectTrigger>
                <SelectContent>
                  <SelectItem value={ALL_VALUE}>All holders</SelectItem>
                  {holderOptions.map((holder) => (
                    <SelectItem key={`${holderTypeFilter}-${holder.id}`} value={holder.id}>
                      {holder.label}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </div>
        </CardContent>
      </Card>

      <DataTable
        columns={columns}
        data={visibleBalances as any}
        searchPlaceholder="Search inventory..."
      />

      {itemId !== ALL_VALUE && rollup && rollup.length > 0 && (
        <Card className="mt-6">
          <CardContent className="pt-6">
            <h3 className="text-lg font-semibold mb-2">Item Rollup</h3>
            {rollup.map((row: any) => (
              <div key={row.itemId} className="space-y-2">
                <p className="text-sm text-muted-foreground">Total across locations</p>
                <p className="text-2xl font-semibold">
                  {row.totalQtyBase} {filteredItems.find((i) => i.id === row.itemId)?.base_uom}
                </p>
                <div className="flex flex-wrap gap-2">
                  {((row.byHolder && row.byHolder.length > 0) ? row.byHolder : row.byLocation).map((loc: any) => (
                    <Badge key={`${loc.holderType || 'OFFICE'}-${loc.holderId || loc.locationId}`} variant="outline">
                      {(() => {
                        const holderType = loc.holderType || 'OFFICE';
                        const holderId = loc.holderId || loc.locationId;
                        if (holderType === 'STORE') return 'Head Office Store';
                        if (holderType === 'EMPLOYEE') {
                          return `${employeeNameMap.get(String(holderId)) || 'Unknown Employee'} (Employee)`;
                        }
                        if (holderType === 'SUB_LOCATION') {
                          return `${sectionNameMap.get(String(holderId)) || 'Unknown Section'} (Section)`;
                        }
                        return filteredLocations.find((l) => l.id === holderId)?.name || 'Unknown Office';
                      })()}: {loc.qtyOnHandBase}
                    </Badge>
                  ))}
                </div>
              </div>
            ))}
          </CardContent>
        </Card>
      )}

      {itemId !== ALL_VALUE && ledger.length > 0 && (
        <Card className="mt-6">
          <CardContent className="pt-6">
            <h3 className="text-lg font-semibold mb-2">Recent Transactions</h3>
            <div className="space-y-2 text-sm">
            {ledger.slice(0, 5).map((entry) => (
              <div key={entry.id} className="flex items-center justify-between border-b pb-2">
                <div>
                  <p className="font-medium">{entry.tx_type}</p>
                  <p className="text-muted-foreground">{new Date(entry.tx_time).toLocaleString()}</p>
                </div>
                <div className="text-right">
                  <p className="font-medium">{entry.qty_base} {filteredItems.find((i) => i.id === entry.consumable_item_id)?.base_uom}</p>
                  <p className="text-muted-foreground">{entry.lot_id ? lots?.find((lot) => lot.id === entry.lot_id)?.batch_no : 'No lot'}</p>
                </div>
              </div>
            ))}
            </div>
          </CardContent>
        </Card>
      )}
    </MainLayout>
  );
}

import { useEffect, useMemo, useState } from 'react';
import { MainLayout } from '@/components/layout/MainLayout';
import { PageHeader } from '@/components/shared/PageHeader';
import { DataTable } from '@/components/shared/DataTable';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Card, CardContent } from '@/components/ui/card';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { useConsumableLedger } from '@/hooks/useConsumableInventory';
import { useConsumableItems } from '@/hooks/useConsumableItems';
import { useOffices } from '@/hooks/useOffices';
import { useEmployees } from '@/hooks/useEmployees';
import { useOfficeSubLocations } from '@/hooks/useOfficeSubLocations';
import { useConsumableLots } from '@/hooks/useConsumableLots';
import type { ConsumableInventoryTransaction } from '@/types';
import { useConsumableMode } from '@/hooks/useConsumableMode';
import { filterItemsByMode, filterLocationsByMode } from '@/lib/consumableMode';
import { ConsumableModeToggle } from '@/components/consumables/ConsumableModeToggle';
import { useAuth } from '@/contexts/AuthContext';

function asId(value: { id?: string; _id?: string }) {
  return value.id || value._id || '';
}

const txTypes = ['RECEIPT', 'TRANSFER', 'CONSUME', 'ADJUST', 'DISPOSE', 'RETURN', 'OPENING_BALANCE'];

function toCsv(rows: any[], columns: string[]) {
  const header = columns.join(',');
  const lines = rows.map((row) =>
    columns.map((key) => `"${String(row[key] ?? '').replace(/"/g, '""')}"`).join(',')
  );
  return [header, ...lines].join('\n');
}

export default function ConsumableLedger() {
  const ALL_VALUE = '__all__';
  const STORE_FILTER = '__store__';
  const STORE_CODE = 'HEAD_OFFICE_STORE';
  const { role, locationId: assignedLocationId } = useAuth();
  const { mode, setMode } = useConsumableMode();
  const { data: items } = useConsumableItems();
  const { data: locations } = useOffices({
    capability: mode === 'chemicals' ? 'chemicals' : 'consumables',
  });
  const { data: employees = [] } = useEmployees();
  const { data: sections = [] } = useOfficeSubLocations();
  const { data: lots } = useConsumableLots();

  const [from, setFrom] = useState('');
  const [to, setTo] = useState('');
  const [locationId, setLocationId] = useState(ALL_VALUE);
  const [itemId, setItemId] = useState(ALL_VALUE);
  const [lotId, setLotId] = useState(ALL_VALUE);
  const [txType, setTxType] = useState(ALL_VALUE);
  const [holderTypeFilter, setHolderTypeFilter] = useState(ALL_VALUE);
  const [holderIdFilter, setHolderIdFilter] = useState(ALL_VALUE);

  const ledgerFilters = useMemo(() => {
    const filters: any = {};
    if (from) filters.from = from;
    if (to) filters.to = to;
    if (holderTypeFilter !== ALL_VALUE && holderIdFilter !== ALL_VALUE) {
      filters.holderType = holderTypeFilter;
      filters.holderId = holderIdFilter;
    } else if (locationId === STORE_FILTER) {
      filters.holderType = 'STORE';
      filters.holderId = STORE_CODE;
    } else if (locationId !== ALL_VALUE) {
      filters.holderType = 'OFFICE';
      filters.holderId = locationId;
    }
    if (itemId !== ALL_VALUE) filters.itemId = itemId;
    if (lotId !== ALL_VALUE) filters.lotId = lotId;
    if (txType !== ALL_VALUE) filters.txType = txType;
    return filters;
  }, [from, to, holderTypeFilter, holderIdFilter, locationId, itemId, lotId, txType, ALL_VALUE, STORE_FILTER, STORE_CODE]);

  const filteredItems = useMemo(() => filterItemsByMode(items || [], mode), [items, mode]);
  const filteredLocations = useMemo(() => filterLocationsByMode(locations || [], mode), [locations, mode]);
  const employeeNameMap = useMemo(
    () =>
      new Map(
        employees.map((employee) => [
          asId(employee),
          `${employee.first_name || ''} ${employee.last_name || ''}`.trim() || employee.email || asId(employee),
        ])
      ),
    [employees]
  );
  const employeeOfficeMap = useMemo(
    () => new Map(employees.map((employee) => [asId(employee), employee.location_id ? String(employee.location_id) : null])),
    [employees]
  );
  const sectionNameMap = useMemo(
    () => new Map(sections.map((section) => [asId(section), section.name])),
    [sections]
  );
  const sectionOfficeMap = useMemo(
    () => new Map(sections.map((section) => [asId(section), section.office_id ? String(section.office_id) : null])),
    [sections]
  );
  const allowedItemIds = useMemo(
    () => new Set(filteredItems.map((item) => item.id)),
    [filteredItems]
  );

  useEffect(() => {
    if (role === 'org_admin') return;
    if (!assignedLocationId) return;
    if (locationId !== assignedLocationId) {
      setLocationId(assignedLocationId);
    }
  }, [role, assignedLocationId, locationId]);

  useEffect(() => {
    setHolderIdFilter(ALL_VALUE);
  }, [holderTypeFilter, ALL_VALUE]);

  const holderOptions = useMemo(() => {
    if (holderTypeFilter === 'STORE') {
      return [{ id: STORE_CODE, label: 'Head Office Store' }];
    }
    if (holderTypeFilter === 'OFFICE') {
      const officeOptions =
        locationId !== ALL_VALUE && locationId !== STORE_FILTER
          ? filteredLocations.filter((location) => location.id === locationId)
          : filteredLocations;
      return officeOptions.map((location) => ({ id: location.id, label: location.name }));
    }
    if (holderTypeFilter === 'EMPLOYEE') {
      return employees
        .filter((employee) => {
          if (locationId === ALL_VALUE || locationId === STORE_FILTER) return true;
          return employee.location_id ? String(employee.location_id) === locationId : false;
        })
        .map((employee) => {
          const employeeId = asId(employee);
          return {
            id: employeeId,
            label: `${employee.first_name || ''} ${employee.last_name || ''}`.trim() || employee.email || employeeId,
          };
        })
        .filter((employee) => employee.id);
    }
    if (holderTypeFilter === 'SUB_LOCATION') {
      return sections
        .filter((section) => {
          const officeId = section.office_id ? String(section.office_id) : null;
          if (locationId === ALL_VALUE || locationId === STORE_FILTER) return true;
          return officeId === locationId;
        })
        .map((section) => ({ id: asId(section), label: section.name }))
        .filter((section) => section.id);
    }
    return [];
  }, [holderTypeFilter, locationId, filteredLocations, employees, sections, ALL_VALUE, STORE_FILTER, STORE_CODE]);

  const { data: ledger = [] } = useConsumableLedger(ledgerFilters);
  const isHolderInOffice = useMemo(
    () =>
      (holderType: string | null | undefined, holderId: string | null | undefined, officeId: string) => {
        if (!holderType || !holderId) return false;
        if (holderType === 'OFFICE') return holderId === officeId;
        if (holderType === 'EMPLOYEE') return employeeOfficeMap.get(holderId) === officeId;
        if (holderType === 'SUB_LOCATION') return sectionOfficeMap.get(holderId) === officeId;
        return false;
      },
    [employeeOfficeMap, sectionOfficeMap]
  );
  const formatHolderLabel = useMemo(
    () =>
      (holderType: string | null | undefined, holderId: string | null | undefined) => {
        if (!holderType || !holderId) return 'N/A';
        if (holderType === 'STORE') return 'Head Office Store';
        if (holderType === 'EMPLOYEE') return `${employeeNameMap.get(holderId) || 'Unknown Employee'} (Employee)`;
        if (holderType === 'SUB_LOCATION') return `${sectionNameMap.get(holderId) || 'Unknown Section'} (Section)`;
        return filteredLocations.find((loc) => loc.id === holderId)?.name || 'Unknown Office';
      },
    [employeeNameMap, sectionNameMap, filteredLocations]
  );

  const visibleLedger = ledger.filter((entry) => {
    if (!filteredItems.some((item) => item.id === entry.consumable_item_id)) return false;
    if (holderTypeFilter !== ALL_VALUE && holderIdFilter !== ALL_VALUE) {
      return (
        (entry.from_holder_type === holderTypeFilter && entry.from_holder_id === holderIdFilter) ||
        (entry.to_holder_type === holderTypeFilter && entry.to_holder_id === holderIdFilter)
      );
    }
    if (locationId === ALL_VALUE) return true;
    if (locationId === STORE_FILTER) {
      return entry.from_holder_type === 'STORE' || entry.to_holder_type === 'STORE';
    }
    return (
      isHolderInOffice(entry.from_holder_type, entry.from_holder_id, locationId) ||
      isHolderInOffice(entry.to_holder_type, entry.to_holder_id, locationId)
    );
  });

  useEffect(() => {
    if (itemId !== ALL_VALUE && !filteredItems.some((item) => item.id === itemId)) {
      setItemId(ALL_VALUE);
      setLotId(ALL_VALUE);
    }
    if (locationId !== ALL_VALUE && locationId !== STORE_FILTER && !filteredLocations.some((loc) => loc.id === locationId)) {
      if (role !== 'org_admin' && assignedLocationId) {
        setLocationId(assignedLocationId);
      } else {
        setLocationId(ALL_VALUE);
      }
    }
  }, [itemId, locationId, filteredItems, filteredLocations, role, assignedLocationId, ALL_VALUE, STORE_FILTER]);

  const columns = [
    { key: 'tx_time', label: 'Date' },
    { key: 'tx_type', label: 'Type' },
    {
      key: 'consumable_item_id',
      label: 'Item',
      render: (value: string) => filteredItems.find((item) => item.id === value)?.name || 'Unknown',
    },
    {
      key: 'lot_id',
      label: 'Lot',
      render: (value: string | null) => value ? lots?.find((lot) => lot.id === value)?.batch_no || 'Unknown' : 'N/A',
    },
    {
      key: 'from_holder_id',
      label: 'From',
      render: (_value: string | null, row: ConsumableInventoryTransaction) => {
        return formatHolderLabel(row.from_holder_type, row.from_holder_id);
      },
    },
    {
      key: 'to_holder_id',
      label: 'To',
      render: (_value: string | null, row: ConsumableInventoryTransaction) => {
        return formatHolderLabel(row.to_holder_type, row.to_holder_id);
      },
    },
    { key: 'qty_base', label: 'Qty (base)' },
  ];

  const handleExport = () => {
    const rows = visibleLedger.map((row) => ({
      date: row.tx_time,
      type: row.tx_type,
      item: filteredItems.find((item) => item.id === row.consumable_item_id)?.name || row.consumable_item_id,
      lot: row.lot_id ? lots?.find((lot) => lot.id === row.lot_id)?.batch_no || row.lot_id : '',
      from: formatHolderLabel(row.from_holder_type, row.from_holder_id),
      to: formatHolderLabel(row.to_holder_type, row.to_holder_id),
      qty_base: row.qty_base,
      entered_qty: row.entered_qty,
      entered_uom: row.entered_uom,
      reason: row.reason_code_id || '',
      reference: row.reference || '',
    }));

    const csv = toCsv(rows, ['date', 'type', 'item', 'lot', 'from', 'to', 'qty_base', 'entered_qty', 'entered_uom', 'reason', 'reference']);
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', 'consumable-ledger.csv');
    document.body.appendChild(link);
    link.click();
    link.remove();
    URL.revokeObjectURL(url);
  };

  return (
    <MainLayout title="Consumable Ledger" description="Transaction history">
      <PageHeader
        title="Ledger"
        description="Filterable transaction history"
        extra={
          <div className="flex items-center gap-2">
            <ConsumableModeToggle mode={mode} onChange={setMode} />
            <Button variant="outline" onClick={handleExport}>Export CSV</Button>
          </div>
        }
      />

      <Card className="mb-6">
        <CardContent className="pt-6">
          <div className="grid grid-cols-1 gap-4 lg:grid-cols-4">
            <div className="space-y-2">
              <label className="text-sm font-medium">From</label>
              <Input type="date" value={from} onChange={(e) => setFrom(e.target.value)} />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium">To</label>
              <Input type="date" value={to} onChange={(e) => setTo(e.target.value)} />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium">Type</label>
              <Select value={txType} onValueChange={setTxType}>
                <SelectTrigger><SelectValue placeholder="All types" /></SelectTrigger>
                <SelectContent>
                  <SelectItem value={ALL_VALUE}>All types</SelectItem>
                  {txTypes.map((type) => (
                    <SelectItem key={type} value={type}>{type}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium">Location</label>
              {role === 'org_admin' ? (
                <Select value={locationId} onValueChange={setLocationId}>
                  <SelectTrigger><SelectValue placeholder="All locations" /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value={ALL_VALUE}>All locations</SelectItem>
                    <SelectItem value={STORE_FILTER}>Head Office Store</SelectItem>
                    {filteredLocations.map((loc) => (
                      <SelectItem key={loc.id} value={loc.id}>{loc.name}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              ) : (
                <div className="rounded-md border bg-muted/30 px-3 py-2 text-sm">
                  {filteredLocations.find((loc) => loc.id === locationId)?.name || 'Assigned location'}
                </div>
              )}
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium">Item</label>
              <Select value={itemId} onValueChange={setItemId}>
                <SelectTrigger><SelectValue placeholder="All items" /></SelectTrigger>
                <SelectContent>
                  <SelectItem value={ALL_VALUE}>All items</SelectItem>
                  {filteredItems.map((item) => (
                    <SelectItem key={item.id} value={item.id}>{item.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium">Lot</label>
              <Select value={lotId} onValueChange={setLotId}>
                <SelectTrigger><SelectValue placeholder="All lots" /></SelectTrigger>
                <SelectContent>
                  <SelectItem value={ALL_VALUE}>All lots</SelectItem>
                  {(lots || [])
                    .filter((lot) => {
                      if (itemId !== ALL_VALUE) return lot.consumable_id === itemId;
                      return allowedItemIds.has(lot.consumable_id);
                    })
                    .map((lot) => (
                      <SelectItem key={lot.id} value={lot.id}>{lot.batch_no}</SelectItem>
                    ))}
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium">Holder Type (optional)</label>
              <Select value={holderTypeFilter} onValueChange={setHolderTypeFilter}>
                <SelectTrigger><SelectValue placeholder="All holder types" /></SelectTrigger>
                <SelectContent>
                  <SelectItem value={ALL_VALUE}>All holder types</SelectItem>
                  <SelectItem value="STORE">Store</SelectItem>
                  <SelectItem value="OFFICE">Office</SelectItem>
                  <SelectItem value="SUB_LOCATION">Section / Room</SelectItem>
                  <SelectItem value="EMPLOYEE">Employee</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium">Holder (optional)</label>
              <Select
                value={holderIdFilter}
                onValueChange={setHolderIdFilter}
                disabled={holderTypeFilter === ALL_VALUE}
              >
                <SelectTrigger><SelectValue placeholder="All holders" /></SelectTrigger>
                <SelectContent>
                  <SelectItem value={ALL_VALUE}>All holders</SelectItem>
                  {holderOptions.map((holder) => (
                    <SelectItem key={`${holderTypeFilter}-${holder.id}`} value={holder.id}>
                      {holder.label}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </div>
        </CardContent>
      </Card>

      <DataTable
        columns={columns}
        data={visibleLedger as ConsumableInventoryTransaction[] as any}
        searchPlaceholder="Search ledger..."
        virtualized
      />
    </MainLayout>
  );
}

