import { DateRangeFilter } from "@/components/reports/DateRangeFilter";
import { Button } from "@/components/ui/button";
import { Download, FileDown } from "lucide-react";
import { toast } from "sonner";
import { useAssets } from "@/hooks/useAssets";
import { useCategories } from "@/hooks/useCategories";
import {
  exportToCSV,
  filterRowsBySearch,
  formatCurrencyForExport,
} from "@/lib/exportUtils";
import { filterByDateRange, generateReportPDF, getDateRangeText } from "@/lib/reporting";
import { usePageSearch } from "@/contexts/PageSearchContext";

export default function FinancialSummaryReport() {
  const [startDate, setStartDate] = useState<Date | undefined>(undefined);
  const [endDate, setEndDate] = useState<Date | undefined>(undefined);
  const pageSearch = usePageSearch();

  const { data: assets } = useAssets();
  const { data: categories } = useCategories({ assetType: "ASSET" });

  const filteredAssets = useMemo(
    () => filterByDateRange(assets, "acquisition_date", startDate, endDate),
    [assets, startDate, endDate]
  );

  const reportRows = useMemo(() => {
    const categoryList = categories || [];
    const totals: Record<string, { count: number; value: number }> = {};

    filteredAssets.forEach((asset) => {
      const category = categoryList.find((c) => c.id === asset.category_id);
      const categoryName = category?.name || "Uncategorized";
      const count = asset.quantity || 0;
      const value = (asset.unit_price || 0) * count;

      if (!totals[categoryName]) {
        totals[categoryName] = { count: 0, value: 0 };
      }
      totals[categoryName].count += count;
      totals[categoryName].value += value;
    });

    const rows = Object.entries(totals).map(([category, data]) => ({
      id: `category-${category}`,
      category,
      assetCount: data.count,
      totalValue: data.value,
    }));

    const grandTotal = rows.reduce((sum, row) => sum + row.totalValue, 0);
    const totalCount = rows.reduce((sum, row) => sum + row.assetCount, 0);

    rows.push({
      id: "grand-total",
      category: "GRAND TOTAL",
      assetCount: totalCount,
      totalValue: grandTotal,
    });

    return rows;
  }, [filteredAssets, categories]);

  const searchTerm = pageSearch?.term || "";
  const filteredRows = useMemo(
    () => filterRowsBySearch(reportRows as any, searchTerm),
    [reportRows, searchTerm]
  );

  const dateRangeText = getDateRangeText(startDate, endDate);
  const filename = `financial-summary-${new Date().toISOString().split("T")[0]}`;

  const columns = [
    {
      key: "category",
      label: "Category",
      render: (value: string) => (
        <span className={value === "GRAND TOTAL" ? "font-semibold" : ""}>{value}</span>
      ),
    },
    {
      key: "assetCount",
      label: "Asset Count",
      render: (value: number, row: any) => (
        <span className={row.category === "GRAND TOTAL" ? "font-semibold" : ""}>{value}</span>
      ),
    },
    {
      key: "totalValue",
      label: "Total Value",
      render: (value: number, row: any) => (
        <span className={row.category === "GRAND TOTAL" ? "font-semibold" : ""}>
          {formatCurrencyForExport(value)}
        </span>
      ),
    },
  ];

  const handleExportCSV = () => {
    if (filteredRows.length === 0) {
      toast.error("No financial data available for the current filters");
      return;
    }

    exportToCSV(
      filteredRows as any,
      [
        { key: "category", header: "Category" },
        { key: "assetCount", header: "Asset Count" },
        { key: "totalValue", header: "Total Value", formatter: (v) => formatCurrencyForExport(v as number) },
      ],
      filename
    );
  };

  const handleExportPDF = () => {
    if (filteredRows.length === 0) {
      toast.error("No financial data available for the current filters");
      return;
    }

    generateReportPDF({
      title: "Financial Summary Report",
      headers: ["Category", "Asset Count", "Total Value"],
      data: filteredRows.map((row) => [
        row.category,
        row.assetCount,
        formatCurrencyForExport(row.totalValue),
      ]),
      filename,
      dateRangeText,
    });
  };

  return (
    <MainLayout title="Financial Summary" description="Asset value and acquisition costs">
      <PageHeader
        title="Financial Summary"
        description="Asset value totals by category"
        extra={
          <div className="flex items-center gap-2">
            <Button variant="outline" className="gap-2" onClick={handleExportCSV}>
              <Download className="h-4 w-4" />
              CSV
            </Button>
            <Button className="gap-2" onClick={handleExportPDF}>
              <FileDown className="h-4 w-4" />
              PDF
            </Button>
          </div>
        }
      />

      <DateRangeFilter
        startDate={startDate}
        endDate={endDate}
        onStartDateChange={setStartDate}
        onEndDateChange={setEndDate}
        onClear={() => {
          setStartDate(undefined);
          setEndDate(undefined);
        }}
        rangeText={dateRangeText}
      />

      <DataTable columns={columns} data={reportRows as any} searchable />
    </MainLayout>
  );
}

import { useMemo, useState } from "react";
import { MainLayout } from "@/components/layout/MainLayout";
import { PageHeader } from "@/components/shared/PageHeader";
import { DataTable } from "@/components/shared/DataTable";
import { DateRangeFilter } from "@/components/reports/DateRangeFilter";
import { Button } from "@/components/ui/button";
import { Download, FileDown } from "lucide-react";
import { toast } from "sonner";
import { useLocations } from "@/hooks/useLocations";
import { useAssetItems } from "@/hooks/useAssetItems";
import { useAssets } from "@/hooks/useAssets";
import {
  exportToCSV,
  filterRowsBySearch,
  formatCurrencyForExport,
} from "@/lib/exportUtils";
import { filterByDateRange, generateReportPDF, getDateRangeText } from "@/lib/reporting";
import { usePageSearch } from "@/contexts/PageSearchContext";
import { getOfficeHolderId, isStoreHolder } from "@/lib/assetItemHolder";

export default function LocationInventoryReport() {
  const [startDate, setStartDate] = useState<Date | undefined>(undefined);
  const [endDate, setEndDate] = useState<Date | undefined>(undefined);
  const pageSearch = usePageSearch();

  const { data: locations } = useLocations();
  const { data: assetItems } = useAssetItems();
  const { data: assets } = useAssets();

  const filteredItems = useMemo(
    () => filterByDateRange(assetItems, "created_at", startDate, endDate),
    [assetItems, startDate, endDate]
  );

  const reportRows = useMemo(() => {
    const locationList = locations || [];
    const assetValueById = new Map((assets || []).map((asset) => [asset.id, asset.unit_price || 0]));
    const itemsByLocation = new Map<string, typeof filteredItems>();
    const storeItems: typeof filteredItems = [];
    filteredItems.forEach((item) => {
      if (isStoreHolder(item)) {
        storeItems.push(item);
        return;
      }
      const officeId = getOfficeHolderId(item);
      if (!officeId) return;
      const existing = itemsByLocation.get(officeId) || [];
      itemsByLocation.set(officeId, [...existing, item]);
    });

    const officeRows = locationList.map((location) => {
      const itemsAtLocation = itemsByLocation.get(location.id) || [];
      const totalValue = itemsAtLocation.reduce((sum, item) => {
        return sum + (assetValueById.get(item.asset_id) || 0);
      }, 0);

      const statusBreakdown = itemsAtLocation.reduce((acc, item) => {
        const status = item.item_status || "Unknown";
        acc[status] = (acc[status] || 0) + 1;
        return acc;
      }, {} as Record<string, number>);

      return {
        id: location.id,
        locationName: location.name,
        address: location.address || "",
        totalItems: itemsAtLocation.length,
        totalValue,
        available: statusBreakdown["Available"] || 0,
        assigned: statusBreakdown["Assigned"] || 0,
        maintenance: statusBreakdown["Maintenance"] || 0,
        damaged: statusBreakdown["Damaged"] || 0,
        retired: statusBreakdown["Retired"] || 0,
      };
    });

    const storeTotalValue = storeItems.reduce((sum, item) => sum + (assetValueById.get(item.asset_id) || 0), 0);
    const storeStatusBreakdown = storeItems.reduce((acc, item) => {
      const status = item.item_status || "Unknown";
      acc[status] = (acc[status] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    return [
      ...officeRows,
      {
        id: "HEAD_OFFICE_STORE",
        locationName: "Head Office Store",
        address: "System Store",
        totalItems: storeItems.length,
        totalValue: storeTotalValue,
        available: storeStatusBreakdown["Available"] || 0,
        assigned: storeStatusBreakdown["Assigned"] || 0,
        maintenance: storeStatusBreakdown["Maintenance"] || 0,
        damaged: storeStatusBreakdown["Damaged"] || 0,
        retired: storeStatusBreakdown["Retired"] || 0,
      },
    ];
  }, [locations, filteredItems, assets]);

  const searchTerm = pageSearch?.term || "";
  const filteredRows = useMemo(
    () => filterRowsBySearch(reportRows as any, searchTerm),
    [reportRows, searchTerm]
  );

  const dateRangeText = getDateRangeText(startDate, endDate);
  const filename = `location-inventory-${new Date().toISOString().split("T")[0]}`;

  const columns = [
    { key: "locationName", label: "Location" },
    { key: "address", label: "Address" },
    { key: "totalItems", label: "Total Items" },
    {
      key: "totalValue",
      label: "Total Value",
      render: (value: number) => formatCurrencyForExport(value),
    },
    { key: "available", label: "Available" },
    { key: "assigned", label: "Assigned" },
    { key: "maintenance", label: "In Maintenance" },
    { key: "damaged", label: "Damaged" },
    { key: "retired", label: "Retired" },
  ];

  const handleExportCSV = () => {
    if (filteredRows.length === 0) {
      toast.error("No location inventory data available for the current filters");
      return;
    }

    exportToCSV(
      filteredRows as any,
      [
        { key: "locationName", header: "Location" },
        { key: "address", header: "Address" },
        { key: "totalItems", header: "Total Items" },
        { key: "totalValue", header: "Total Value", formatter: (v) => formatCurrencyForExport(v as number) },
        { key: "available", header: "Available" },
        { key: "assigned", header: "Assigned" },
        { key: "maintenance", header: "In Maintenance" },
        { key: "damaged", header: "Damaged" },
        { key: "retired", header: "Retired" },
      ],
      filename
    );
  };

  const handleExportPDF = () => {
    if (filteredRows.length === 0) {
      toast.error("No location inventory data available for the current filters");
      return;
    }

    generateReportPDF({
      title: "Location Inventory Report",
      headers: ["Location", "Items", "Value", "Available", "Assigned", "Maintenance", "Damaged"],
      data: filteredRows.map((row) => [
        row.locationName,
        row.totalItems,
        formatCurrencyForExport(row.totalValue),
        row.available,
        row.assigned,
        row.maintenance,
        row.damaged,
      ]),
      filename,
      dateRangeText,
    });
  };

  return (
    <MainLayout title="Location Inventory" description="Inventory by location">
      <PageHeader
        title="Location Inventory"
        description="Detailed inventory totals by physical location"
        extra={
          <div className="flex items-center gap-2">
            <Button variant="outline" className="gap-2" onClick={handleExportCSV}>
              <Download className="h-4 w-4" />
              CSV
            </Button>
            <Button className="gap-2" onClick={handleExportPDF}>
              <FileDown className="h-4 w-4" />
              PDF
            </Button>
          </div>
        }
      />

      <DateRangeFilter
        startDate={startDate}
        endDate={endDate}
        onStartDateChange={setStartDate}
        onEndDateChange={setEndDate}
        onClear={() => {
          setStartDate(undefined);
          setEndDate(undefined);
        }}
        rangeText={dateRangeText}
      />

      <DataTable columns={columns} data={reportRows as any} searchable />
    </MainLayout>
  );
}

import { useMemo, useState } from "react";
import { MainLayout } from "@/components/layout/MainLayout";
import { PageHeader } from "@/components/shared/PageHeader";
import { DataTable } from "@/components/shared/DataTable";
import { DateRangeFilter } from "@/components/reports/DateRangeFilter";
import { Button } from "@/components/ui/button";
import { Download, FileDown } from "lucide-react";
import { toast } from "sonner";
import { useMaintenance } from "@/hooks/useMaintenance";
import { useAssetItems } from "@/hooks/useAssetItems";
import { useAssets } from "@/hooks/useAssets";
import {
  exportToCSV,
  filterRowsBySearch,
  formatCurrencyForExport,
  formatDateForExport,
} from "@/lib/exportUtils";
import { filterByDateRange, generateReportPDF, getDateRangeText } from "@/lib/reporting";
import { usePageSearch } from "@/contexts/PageSearchContext";

export default function MaintenanceReport() {
  const [startDate, setStartDate] = useState<Date | undefined>(undefined);
  const [endDate, setEndDate] = useState<Date | undefined>(undefined);
  const pageSearch = usePageSearch();

  const { data: maintenance } = useMaintenance();
  const { data: assetItems } = useAssetItems();
  const { data: assets } = useAssets();

  const filteredMaintenance = useMemo(
    () => filterByDateRange(maintenance, "scheduled_date", startDate, endDate),
    [maintenance, startDate, endDate]
  );

  const reportRows = useMemo(() => {
    const itemList = assetItems || [];
    const assetList = assets || [];

    return filteredMaintenance.map((record) => {
      const assetItem = itemList.find((i) => i.id === record.asset_item_id);
      const asset = assetItem ? assetList.find((a) => a.id === assetItem.asset_id) : undefined;

      return {
        id: record.id,
        assetTag: assetItem?.tag || "N/A",
        assetName: asset?.name || "Unknown",
        maintenanceType: record.maintenance_type || "N/A",
        status: record.maintenance_status || "N/A",
        scheduledDate: record.scheduled_date,
        completedDate: record.completed_date,
        performedBy: record.performed_by || "",
        cost: record.cost || 0,
      };
    });
  }, [filteredMaintenance, assetItems, assets]);

  const searchTerm = pageSearch?.term || "";
  const filteredRows = useMemo(
    () => filterRowsBySearch(reportRows as any, searchTerm),
    [reportRows, searchTerm]
  );

  const dateRangeText = getDateRangeText(startDate, endDate);
  const filename = `maintenance-report-${new Date().toISOString().split("T")[0]}`;

  const columns = [
    { key: "assetTag", label: "Asset Tag" },
    { key: "assetName", label: "Asset Name" },
    { key: "maintenanceType", label: "Type" },
    { key: "status", label: "Status" },
    {
      key: "scheduledDate",
      label: "Scheduled",
      render: (value: string) => formatDateForExport(value),
    },
    {
      key: "completedDate",
      label: "Completed",
      render: (value: string) => formatDateForExport(value),
    },
    {
      key: "cost",
      label: "Cost",
      render: (value: number) => formatCurrencyForExport(value),
    },
    { key: "performedBy", label: "Performed By" },
  ];

  const handleExportCSV = () => {
    if (filteredRows.length === 0) {
      toast.error("No maintenance records available for the current filters");
      return;
    }

    exportToCSV(
      filteredRows as any,
      [
        { key: "assetTag", header: "Asset Tag" },
        { key: "assetName", header: "Asset Name" },
        { key: "maintenanceType", header: "Type" },
        { key: "status", header: "Status" },
        { key: "scheduledDate", header: "Scheduled Date", formatter: (v) => formatDateForExport(v as string) },
        { key: "completedDate", header: "Completed Date", formatter: (v) => formatDateForExport(v as string) },
        { key: "cost", header: "Cost", formatter: (v) => formatCurrencyForExport(v as number) },
        { key: "performedBy", header: "Performed By" },
      ],
      filename
    );
  };

  const handleExportPDF = () => {
    if (filteredRows.length === 0) {
      toast.error("No maintenance records available for the current filters");
      return;
    }

    generateReportPDF({
      title: "Maintenance Report",
      headers: ["Tag", "Asset", "Type", "Status", "Scheduled", "Completed", "Cost"],
      data: filteredRows.map((row) => [
        row.assetTag,
        row.assetName,
        row.maintenanceType,
        row.status,
        formatDateForExport(row.scheduledDate),
        formatDateForExport(row.completedDate),
        formatCurrencyForExport(row.cost),
      ]),
      filename,
      dateRangeText,
    });
  };

  return (
    <MainLayout title="Maintenance Report" description="Maintenance records and costs">
      <PageHeader
        title="Maintenance Report"
        description="Maintenance records, schedules, and costs"
        extra={
          <div className="flex items-center gap-2">
            <Button variant="outline" className="gap-2" onClick={handleExportCSV}>
              <Download className="h-4 w-4" />
              CSV
            </Button>
            <Button className="gap-2" onClick={handleExportPDF}>
              <FileDown className="h-4 w-4" />
              PDF
            </Button>
          </div>
        }
      />

      <DateRangeFilter
        startDate={startDate}
        endDate={endDate}
        onStartDateChange={setStartDate}
        onEndDateChange={setEndDate}
        onClear={() => {
          setStartDate(undefined);
          setEndDate(undefined);
        }}
        rangeText={dateRangeText}
      />

      <DataTable columns={columns} data={reportRows as any} searchable />
    </MainLayout>
  );
}

import { useMemo, useState } from "react";
import { MainLayout } from "@/components/layout/MainLayout";
import { PageHeader } from "@/components/shared/PageHeader";
import { DataTable } from "@/components/shared/DataTable";
import { DateRangeFilter } from "@/components/reports/DateRangeFilter";
import { Button } from "@/components/ui/button";
import { Download, FileDown } from "lucide-react";
import { toast } from "sonner";
import { useAssetItems } from "@/hooks/useAssetItems";
import { exportToCSV, filterRowsBySearch } from "@/lib/exportUtils";
import { filterByDateRange, generateReportPDF, getDateRangeText } from "@/lib/reporting";
import { usePageSearch } from "@/contexts/PageSearchContext";

export default function StatusDistributionReport() {
  const [startDate, setStartDate] = useState<Date | undefined>(undefined);
  const [endDate, setEndDate] = useState<Date | undefined>(undefined);
  const pageSearch = usePageSearch();

  const { data: assetItems } = useAssetItems();

  const filteredItems = useMemo(
    () => filterByDateRange(assetItems, "created_at", startDate, endDate),
    [assetItems, startDate, endDate]
  );

  const reportRows = useMemo(() => {
    if (filteredItems.length === 0) return [];

    const statusCounts: Record<string, number> = {};
    const conditionCounts: Record<string, number> = {};
    const assignmentCounts: Record<string, number> = {};

    filteredItems.forEach((item) => {
      const status = item.item_status || "Unknown";
      const condition = item.item_condition || "Unknown";
      const assignment = item.assignment_status || "Unknown";

      statusCounts[status] = (statusCounts[status] || 0) + 1;
      conditionCounts[condition] = (conditionCounts[condition] || 0) + 1;
      assignmentCounts[assignment] = (assignmentCounts[assignment] || 0) + 1;
    });

    const total = filteredItems.length;
    const rows: Array<{ id: string; category: string; type: string; count: number; percentage: string }> = [];

    Object.entries(statusCounts).forEach(([type, count]) => {
      rows.push({
        id: `status-${type}`,
        category: "Status",
        type,
        count,
        percentage: ((count / total) * 100).toFixed(1) + "%",
      });
    });

    Object.entries(conditionCounts).forEach(([type, count]) => {
      rows.push({
        id: `condition-${type}`,
        category: "Condition",
        type,
        count,
        percentage: ((count / total) * 100).toFixed(1) + "%",
      });
    });

    Object.entries(assignmentCounts).forEach(([type, count]) => {
      rows.push({
        id: `assignment-${type}`,
        category: "Assignment",
        type,
        count,
        percentage: ((count / total) * 100).toFixed(1) + "%",
      });
    });

    return rows;
  }, [filteredItems]);

  const searchTerm = pageSearch?.term || "";
  const filteredRows = useMemo(
    () => filterRowsBySearch(reportRows as any, searchTerm),
    [reportRows, searchTerm]
  );

  const dateRangeText = getDateRangeText(startDate, endDate);
  const filename = `status-distribution-${new Date().toISOString().split("T")[0]}`;

  const columns = [
    { key: "category", label: "Category" },
    { key: "type", label: "Type" },
    { key: "count", label: "Count" },
    { key: "percentage", label: "Percentage" },
  ];

  const handleExportCSV = () => {
    if (filteredRows.length === 0) {
      toast.error("No asset item data available for the current filters");
      return;
    }

    exportToCSV(
      filteredRows as any,
      [
        { key: "category", header: "Category" },
        { key: "type", header: "Type" },
        { key: "count", header: "Count" },
        { key: "percentage", header: "Percentage" },
      ],
      filename
    );
  };

  const handleExportPDF = () => {
    if (filteredRows.length === 0) {
      toast.error("No asset item data available for the current filters");
      return;
    }

    generateReportPDF({
      title: "Status Distribution Report",
      headers: ["Category", "Type", "Count", "Percentage"],
      data: filteredRows.map((row) => [row.category, row.type, row.count, row.percentage]),
      filename,
      dateRangeText,
    });
  };

  return (
    <MainLayout title="Status Distribution" description="Distribution of item status and condition">
      <PageHeader
        title="Status Distribution"
        description="Status, condition, and assignment distribution across asset items"
        extra={
          <div className="flex items-center gap-2">
            <Button variant="outline" className="gap-2" onClick={handleExportCSV}>
              <Download className="h-4 w-4" />
              CSV
            </Button>
            <Button className="gap-2" onClick={handleExportPDF}>
              <FileDown className="h-4 w-4" />
              PDF
            </Button>
          </div>
        }
      />

      <DateRangeFilter
        startDate={startDate}
        endDate={endDate}
        onStartDateChange={setStartDate}
        onEndDateChange={setEndDate}
        onClear={() => {
          setStartDate(undefined);
          setEndDate(undefined);
        }}
        rangeText={dateRangeText}
      />

      <DataTable columns={columns} data={reportRows as any} searchable />
    </MainLayout>
  );
}
